@app.post("/genesys/users/build-webrtc-batch")
def genesys_build_webrtc_batch_route(users_json: str = Form("")):
  started_at = time.time()
  clean_region = (GENESYS_CLOUD_REGION or "usw2").strip().lower() or "usw2"

  try:
    parsed_users = json.loads(users_json or "[]")
  except Exception:
    return JSONResponse({"ok": False, "error": "users_json must be valid JSON."}, status_code=400)

  if not isinstance(parsed_users, list) or not parsed_users:
    return JSONResponse({"ok": False, "error": "At least one user is required."}, status_code=400)

  if len(parsed_users) > 100:
    return JSONResponse({"ok": False, "error": "Batch limit is 100 users per request."}, status_code=400)

  users = []
  for entry in parsed_users:
    if not isinstance(entry, dict):
      continue
    clean_user_id = str(entry.get("user_id", "") or "").strip()
    clean_user_name = str(entry.get("user_name", "") or "").strip()
    clean_user_email = str(entry.get("user_email", "") or "").strip().lower()
    if not clean_user_id and not clean_user_email:
      continue
    users.append({"user_id": clean_user_id, "user_name": clean_user_name, "user_email": clean_user_email})

  if not users:
    return JSONResponse({"ok": False, "error": "No valid users were provided."}, status_code=400)

  token_result = _genesys_get_access_token(clean_region, GENESYS_CLIENT_ID, GENESYS_CLIENT_SECRET)
  if not token_result.get("ok"):
    return JSONResponse({
      "ok": False,
      "error": token_result.get("error", "Genesys token request failed."),
    }, status_code=400)

  region = token_result.get("region", clean_region)
  access_token = token_result.get("access_token", "")
  max_workers = 3

  def _build_one(index: int, user: dict) -> tuple[int, dict]:
    try:
      build_result = _genesys_build_webrtc_phone_for_user(
        region,
        access_token,
        user["user_id"],
        user["user_name"],
        user.get("user_email", ""),
      )
      if build_result.get("ok"):
        return index, {
          "ok": True,
          "user_id": user["user_id"],
          "user_name": user["user_name"],
          "user_email": user.get("user_email", ""),
          "phone_id": build_result.get("phone_id", ""),
          "phone_name": build_result.get("phone_name", ""),
          "create_mode": build_result.get("create_mode", ""),
          "association_result": build_result.get("association_result", ""),
          "already_present": bool(build_result.get("already_present", False)),
        }
      return index, {
        "ok": False,
        "user_id": user["user_id"],
        "user_name": user["user_name"],
        "user_email": user.get("user_email", ""),
        "error": build_result.get("error", "WebRTC phone build failed."),
      }
    except Exception as exc:
      return index, {
        "ok": False,
        "user_id": user.get("user_id", ""),
        "user_name": user.get("user_name", ""),
        "user_email": user.get("user_email", ""),
        "error": f"Unhandled bulk worker error: {exc}",
      }

  indexed_results = [None] * len(users)
  with concurrent.futures.ThreadPoolExecutor(max_workers=max_workers) as executor:
    future_map = {
      executor.submit(_build_one, idx, user): idx
      for idx, user in enumerate(users)
    }
    for future in concurrent.futures.as_completed(future_map):
      index, row = future.result()
      indexed_results[index] = row

  results = [row for row in indexed_results if isinstance(row, dict)]
  success_count = sum(1 for row in results if row.get("ok"))

  failure_count = len(results) - success_count
  requested = len(users)
  status = "completed" if failure_count == 0 else "completed_with_failures"

  original_emails = []
  seen_original = set()
  for user in users:
    email = str(user.get("user_email", "") or "").strip().lower()
    if not email or email in seen_original:
      continue
    seen_original.add(email)
    original_emails.append(email)

  failed_emails = []
  seen_failed = set()
  for row in results:
    if row.get("ok"):
      continue
    email = str(row.get("user_email", "") or "").strip().lower()
    if not email or email in seen_failed:
      continue
    seen_failed.add(email)
    failed_emails.append(email)

  timestamp_token = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
  original_text = "\n".join(original_emails) + ("\n" if original_emails else "")
  failed_text = "\n".join(failed_emails) + ("\n" if failed_emails else "")

  original_job_id = _store_job_output(
    original_text.encode("utf-8"),
    f"genesys_bulk_original_emails_{timestamp_token}.txt",
    "text/plain",
  )
  failed_job_id = _store_job_output(
    failed_text.encode("utf-8"),
    f"genesys_bulk_failed_emails_{timestamp_token}.txt",
    "text/plain",
  )
  original_download_url = f"/download/job-output/{original_job_id}"
  failed_download_url = f"/download/job-output/{failed_job_id}"

  duration_seconds = max(0.0, time.time() - started_at)
  _append_genesys_bulk_history_event(
    status=status,
    requested=requested,
    success_count=success_count,
    failure_count=failure_count,
    workers=max_workers,
    duration_seconds=duration_seconds,
    original_emails=original_emails,
    failed_emails=failed_emails,
    original_download_url=original_download_url,
    failed_download_url=failed_download_url,
  )

  return JSONResponse({
    "ok": True,
    "region": region,
    "requested": requested,
    "workers": max_workers,
    "status": status,
    "duration_seconds": round(duration_seconds, 2),
    "success_count": success_count,
    "failure_count": failure_count,
    "original_emails": original_emails,
    "failed_emails": failed_emails,
    "original_emails_download_url": original_download_url,
    "failed_emails_download_url": failed_download_url,
    "results": results,
  })


