@app.post("/genesys/users/build-webrtc-emails")
def genesys_build_webrtc_emails_route(request: Request, email_list: str = Form("")):
  """Server-side fallback for bulk email build when browser JS is unavailable/broken."""
  text_value = (email_list or "").strip()
  if not text_value:
    return RedirectResponse(url="/genesys-admin", status_code=303)

  # Normalize like the browser path: split on whitespace/comma/semicolon and de-dup.
  candidates = re.split(r"[\n,;\s]+", text_value)
  seen = set()
  users = []
  for raw in candidates:
    email = str(raw or "").strip().lower()
    if not email or "@" not in email or email in seen:
      continue
    seen.add(email)
    users.append({"user_id": "", "user_name": "", "user_email": email})

  if not users:
    return RedirectResponse(url="/genesys-admin", status_code=303)

  # Reuse existing batch logic directly (single token, same behavior).
  batch_resp = genesys_build_webrtc_batch_route(users_json=json.dumps(users))
  payload = {}
  try:
    payload = json.loads(batch_resp.body.decode("utf-8")) if getattr(batch_resp, "body", None) else {}
  except Exception:
    payload = {}

  # Persist one-line summary for immediate operator feedback in the page.
  session = _get_auth_session(request) or {}
  if isinstance(session, dict):
    if payload.get("ok"):
      session["genesys_bulk_flash"] = (
        f"Bulk build complete: Processed {int(payload.get('success_count', 0))} of {int(payload.get('requested', len(users)))} email(s). "
        f"Failed: {int(payload.get('failure_count', 0))}."
      )
    else:
      session["genesys_bulk_flash"] = str(payload.get("error", "Bulk build failed."))

  return RedirectResponse(url="/genesys-admin", status_code=303)


@app.post("/genesys/users/queues-by-id")
def genesys_user_queues_by_id_route(
  user_id: str = Form(""),
  user_name: str = Form(""),
  user_email: str = Form(""),
):
  clean_user_id = (user_id or "").strip()
  clean_user_name = (user_name or "").strip()
  clean_user_email = (user_email or "").strip()
  clean_region = (GENESYS_CLOUD_REGION or "usw2").strip().lower() or "usw2"

  if not clean_user_id:
    return JSONResponse({"ok": False, "error": "user_id is required."}, status_code=400)

  token_result = _genesys_get_queue_access_token(clean_region)
  if not token_result.get("ok"):
    return JSONResponse({
      "ok": False,
      "error": token_result.get("error", "Genesys token request failed."),
    }, status_code=400)

  region = token_result.get("region", clean_region)
  _, _, api_base = _genesys_region_to_urls(region)
  access_token = token_result.get("access_token", "")

  warnings = []
  queue_names = []
  queue_resolution_source = "none"

  # Fetch profile to improve fallback matching when caller only provides user_id.
  ok_user, user_payload, err_user = _genesys_get_json(api_base, access_token, f"/api/v2/users/{clean_user_id}")
  if ok_user:
    clean_user_name = clean_user_name or str(user_payload.get("name", "") or "").strip()
    clean_user_email = clean_user_email or str(user_payload.get("email", "") or "").strip()
  elif err_user:
    warnings.append(f"user profile: {err_user}")

  user_queue_entities, err_queues, user_queue_pages = _genesys_get_user_queues_paged(api_base, access_token, clean_user_id)
  if not err_queues:
    entities = user_queue_entities or []
    queue_ids = []
    for item in entities:
      if not isinstance(item, dict):
        continue

      queue_obj = item.get("queue") if isinstance(item.get("queue"), dict) else {}
      q_name = str(item.get("name", "") or queue_obj.get("name", "") or "").strip()
      q_id = str(item.get("id", "") or item.get("queueId", "") or queue_obj.get("id", "") or "").strip()
      if q_name:
        queue_names.append(q_name)
      elif q_id:
        queue_ids.append(q_id)

    if not queue_names and queue_ids:
      for q_id in queue_ids:
        resolved_name = _genesys_get_queue_name(api_base, access_token, q_id)
        if resolved_name:
          queue_names.append(resolved_name)

    if queue_names:
      queue_resolution_source = "direct-user-queues"

  if not queue_names:
    fallback_queue_names, fallback_queue_err, fallback_queue_diag = _genesys_lookup_user_queues_via_membership(
      api_base,
      access_token,
      clean_user_id,
      clean_user_email,
      clean_user_name,
    )
    if fallback_queue_names:
      queue_names = list(fallback_queue_names)
      queue_resolution_source = "membership-fallback" if not err_queues else "membership-fallback-after-direct-error"
    elif fallback_queue_err:
      warnings.append(f"queue membership fallback: {fallback_queue_err}")
    if isinstance(fallback_queue_diag, dict):
      fallback_queue_diag["direct_user_queue_pages_scanned"] = int(user_queue_pages or 0)
      scanned_count = int(fallback_queue_diag.get("scanned_queue_count", 0) or 0)
      scanned_pages = int(fallback_queue_diag.get("scanned_queue_pages", 0) or 0)
      if scanned_count == 0:
        warnings.append(f"queue visibility: 0 queues visible to API client (pages_scanned={scanned_pages})")

  if err_queues:
    warnings.append(f"direct user queues: {err_queues}")

  queue_names = sorted(set([q for q in queue_names if str(q or "").strip()]), key=str.lower)
  return JSONResponse({
    "ok": True,
    "region": region,
    "user_id": clean_user_id,
    "user_name": clean_user_name,
    "user_email": clean_user_email,
    "queues": queue_names,
    "queue_resolution_source": queue_resolution_source,
    "queue_diagnostics": fallback_queue_diag if isinstance(locals().get("fallback_queue_diag"), dict) else {},
    "warnings": warnings,
  })


@app.get("/genesys/catalog/options")
def genesys_catalog_options_route():
  clean_region = (GENESYS_CLOUD_REGION or "usw2").strip().lower() or "usw2"
  token_result = _genesys_get_queue_access_token(clean_region)
  if not token_result.get("ok"):
    return JSONResponse({
      "ok": False,
      "error": token_result.get("error", "Genesys token request failed."),
    }, status_code=400)

  primary_catalog = _genesys_load_catalog_options(
    token_result.get("region", clean_region),
    token_result.get("access_token", ""),
  )

  best_catalog = primary_catalog
  best_source = str(token_result.get("token_source", "") or "default-client")

  def _norm_name(value: str) -> str:
    return re.sub(r"[^a-z0-9]+", "", " ".join(str(value or "").strip().lower().split()))

  def _merge_options(base_rows: list[dict], extra_rows: list[dict]) -> list[dict]:
    merged = []
    seen = set()

    def _key(row: dict) -> str:
      if not isinstance(row, dict):
        return ""
      row_id = str(row.get("id", "") or "").strip().lower()
      row_name = _norm_name(str(row.get("name", "") or ""))
      if row_id:
        return "id:" + row_id
      if row_name:
        return "name:" + row_name
      return ""

    for rows in [base_rows, extra_rows]:
      for row in (rows or []):
        if not isinstance(row, dict):
          continue
        k = _key(row)
        if not k or k in seen:
          continue
        seen.add(k)
        merged.append(dict(row))

    return merged

  def _sanitize_options(rows: list[dict]) -> list[dict]:
    cleaned = []
    seen = set()
    for row in (rows or []):
      if not isinstance(row, dict):
        continue
      row_id = str(row.get("id", "") or "").strip()
      row_name = str(row.get("name", "") or "").strip()
      if not row_id:
        continue
      if "(missing in api catalog)" in row_name.lower():
        continue
      dedupe_key = (row_id.lower(), row_name.lower())
      if dedupe_key in seen:
        continue
      seen.add(dedupe_key)
      cleaned.append(dict(row))
    return cleaned

  def _recompute_priority_counts(catalog: dict):
    queues = catalog.get("queues", []) if isinstance(catalog.get("queues"), list) else []
    skills = catalog.get("skills", []) if isinstance(catalog.get("skills"), list) else []
    catalog["important_queue_count"] = int(sum(1 for item in queues if isinstance(item, dict) and item.get("priority")))
    catalog["important_skill_count"] = int(sum(1 for item in skills if isinstance(item, dict) and item.get("priority")))

  def _recompute_missing(catalog: dict):
    skill_targets = {
      _norm_name(name): str(name or "").strip()
      for name in GENESYS_IMPORTANT_SKILL_NAMES
      if str(name or "").strip()
    }
    queue_targets = {
      _norm_name(name): str(name or "").strip()
      for name in GENESYS_IMPORTANT_QUEUE_NAMES
      if str(name or "").strip()
    }

    found_skills = {
      _norm_name(str(item.get("name", "") or ""))
      for item in (catalog.get("skills", []) if isinstance(catalog.get("skills"), list) else [])
      if isinstance(item, dict)
    }
    found_queues = {
      _norm_name(str(item.get("name", "") or ""))
      for item in (catalog.get("queues", []) if isinstance(catalog.get("queues"), list) else [])
      if isinstance(item, dict)
    }

    missing_skills = [
      skill_targets[key]
      for key in sorted(skill_targets.keys())
      if key and key not in found_skills
    ]
    missing_queues = [
      queue_targets[key]
      for key in sorted(queue_targets.keys())
      if key and key not in found_queues
    ]
    catalog["missing_important_skills"] = missing_skills
    catalog["missing_important_queues"] = missing_queues

    warnings = list(catalog.get("warnings", []) if isinstance(catalog.get("warnings"), list) else [])
    warnings = [w for w in warnings if "important skills not found:" not in str(w) and "important queues not found:" not in str(w)]
    if missing_skills:
      warnings.append("important skills not found: " + ", ".join(missing_skills))
    if missing_queues:
      warnings.append("important queues not found: " + ", ".join(missing_queues))
    catalog["warnings"] = warnings

  # If queue-client is used, compare against default client and keep whichever
  # yields broader queue/skill visibility.
  has_default_creds = bool((GENESYS_CLIENT_ID or "").strip()) and bool((GENESYS_CLIENT_SECRET or "").strip())
  if has_default_creds and best_source == "queue-client":
    default_token = _genesys_get_access_token(clean_region, GENESYS_CLIENT_ID, GENESYS_CLIENT_SECRET)
    if default_token.get("ok"):
      default_catalog = _genesys_load_catalog_options(
        default_token.get("region", clean_region),
        default_token.get("access_token", ""),
      )
      if default_catalog.get("ok"):
        primary_queue_count = len(best_catalog.get("queues", []) if isinstance(best_catalog.get("queues"), list) else [])
        default_queue_count = len(default_catalog.get("queues", []) if isinstance(default_catalog.get("queues"), list) else [])
        primary_skill_count = len(best_catalog.get("skills", []) if isinstance(best_catalog.get("skills"), list) else [])
        default_skill_count = len(default_catalog.get("skills", []) if isinstance(default_catalog.get("skills"), list) else [])
        primary_missing_queue = len(best_catalog.get("missing_important_queues", []) if isinstance(best_catalog.get("missing_important_queues"), list) else [])
        default_missing_queue = len(default_catalog.get("missing_important_queues", []) if isinstance(default_catalog.get("missing_important_queues"), list) else [])

        use_default = (
          (default_queue_count > primary_queue_count)
          or (default_skill_count > primary_skill_count)
          or (default_missing_queue < primary_missing_queue)
        )

        if use_default:
          best_catalog = default_catalog
          best_source = "default-client"
          warns = list(best_catalog.get("warnings", []) if isinstance(best_catalog.get("warnings"), list) else [])
          warns.append(
            f"Catalog source switched to default-client for broader visibility (queues {default_queue_count} vs {primary_queue_count})."
          )
          best_catalog["warnings"] = warns
        else:
          warns = list(best_catalog.get("warnings", []) if isinstance(best_catalog.get("warnings"), list) else [])
          warns.append(
            f"Queue-client catalog retained (queues {primary_queue_count}); default-client returned queues {default_queue_count}."
          )
          best_catalog["warnings"] = warns

        # Merge both source catalogs so we keep the broadest visible set.
        merged_catalog = dict(best_catalog)
        merged_catalog["divisions"] = _merge_options(
          best_catalog.get("divisions", []) if isinstance(best_catalog.get("divisions"), list) else [],
          default_catalog.get("divisions", []) if isinstance(default_catalog.get("divisions"), list) else [],
        )
        merged_catalog["skills"] = _merge_options(
          best_catalog.get("skills", []) if isinstance(best_catalog.get("skills"), list) else [],
          default_catalog.get("skills", []) if isinstance(default_catalog.get("skills"), list) else [],
        )
        merged_catalog["queues"] = _merge_options(
          best_catalog.get("queues", []) if isinstance(best_catalog.get("queues"), list) else [],
          default_catalog.get("queues", []) if isinstance(default_catalog.get("queues"), list) else [],
        )
        merged_catalog["divisions"] = _sanitize_options(merged_catalog.get("divisions", []))
        merged_catalog["skills"] = _sanitize_options(merged_catalog.get("skills", []))
        merged_catalog["queues"] = _sanitize_options(merged_catalog.get("queues", []))

        primary_pages = best_catalog.get("pages_scanned", {}) if isinstance(best_catalog.get("pages_scanned"), dict) else {}
        default_pages = default_catalog.get("pages_scanned", {}) if isinstance(default_catalog.get("pages_scanned"), dict) else {}
        merged_catalog["pages_scanned"] = {
          "divisions": int(primary_pages.get("divisions", 0) or 0) + int(default_pages.get("divisions", 0) or 0),
          "skills": int(primary_pages.get("skills", 0) or 0) + int(default_pages.get("skills", 0) or 0),
          "queues": int(primary_pages.get("queues", 0) or 0) + int(default_pages.get("queues", 0) or 0),
        }

        _recompute_priority_counts(merged_catalog)
        _recompute_missing(merged_catalog)

        merged_warnings = list(merged_catalog.get("warnings", []) if isinstance(merged_catalog.get("warnings"), list) else [])
        merged_warnings.append(
          "Catalog merged across queue-client and default-client visibility for broader queue/skill coverage."
        )
        merged_catalog["warnings"] = merged_warnings

        best_catalog = merged_catalog
        best_source = "merged:queue-client+default-client"

  if not best_catalog.get("ok"):
    return JSONResponse({
      "ok": False,
      "error": "Unable to load catalog options from Genesys.",
      "warnings": best_catalog.get("warnings", []),
    }, status_code=400)

  best_catalog["divisions"] = _sanitize_options(best_catalog.get("divisions", []))
  best_catalog["skills"] = _sanitize_options(best_catalog.get("skills", []))
  best_catalog["queues"] = _sanitize_options(best_catalog.get("queues", []))
  _recompute_priority_counts(best_catalog)
  _recompute_missing(best_catalog)

  best_catalog["token_source"] = best_source

  raw_payload = {
    "region": best_catalog.get("region", clean_region),
    "token_source": best_catalog.get("token_source", best_source),
    "pages_scanned": best_catalog.get("pages_scanned", {}),
    "warnings": best_catalog.get("warnings", []),
    "divisions": best_catalog.get("divisions", []),
    "skills": best_catalog.get("skills", []),
    "queues": best_catalog.get("queues", []),
    "missing_important_skills": best_catalog.get("missing_important_skills", []),
    "missing_important_queues": best_catalog.get("missing_important_queues", []),
  }
  raw_filename = f"genesys_catalog_options_{datetime.datetime.now().strftime('%Y%m%d_%H%M%S')}.json"
  raw_job_id = _store_job_output(
    json.dumps(raw_payload, indent=2).encode("utf-8"),
    raw_filename,
    "application/json",
  )
  best_catalog["raw_download_url"] = f"/download/job-output/{raw_job_id}"
  best_catalog["raw_filename"] = raw_filename

  return JSONResponse(best_catalog)


@app.get("/genesys/division-filters")
def genesys_division_filters_route():
  payload = _load_genesys_division_filters()
  filters = payload.get("filters", {}) if isinstance(payload, dict) else {}
  rows = []
  for division_id, item in (filters.items() if isinstance(filters, dict) else []):
    if not isinstance(item, dict):
      continue
    rows.append({
      "division_id": str(division_id or "").strip(),
      "filter_name": str(item.get("filter_name", "") or item.get("division_name", "") or "").strip(),
      "division_name": str(item.get("division_name", "") or "").strip(),
      "skill_ids": list(item.get("skill_ids", []) if isinstance(item.get("skill_ids"), list) else []),
      "queue_ids": list(item.get("queue_ids", []) if isinstance(item.get("queue_ids"), list) else []),
      "enabled": bool(item.get("enabled", True)),
      "updated_at": str(item.get("updated_at", "") or "").strip(),
    })
  rows.sort(key=lambda row: (str(row.get("filter_name", "") or row.get("division_name", "") or "").lower(), str(row.get("division_id", "") or "").lower()))
  return JSONResponse({
    "ok": True,
    "filters": rows,
    "path": GENESYS_DIVISION_FILTERS_PATH,
  })


@app.post("/genesys/division-filters/save")
def genesys_division_filters_save_route(
  division_id: str = Form(""),
  filter_name: str = Form(""),
  division_name: str = Form(""),
  skill_ids_json: str = Form("[]"),
  queue_ids_json: str = Form("[]"),
  enabled: str = Form("true"),
):
  clean_division_id = str(division_id or "").strip()
  clean_filter_name = str(filter_name or "").strip()
  clean_division_name = str(division_name or "").strip()
  if not clean_filter_name:
    clean_filter_name = clean_division_name
  if not clean_division_id:
    return JSONResponse({"ok": False, "error": "division_id is required."}, status_code=400)

  try:
    skill_ids = json.loads(skill_ids_json or "[]")
  except Exception:
    skill_ids = []
  try:
    queue_ids = json.loads(queue_ids_json or "[]")
  except Exception:
    queue_ids = []

  if not isinstance(skill_ids, list):
    skill_ids = []
  if not isinstance(queue_ids, list):
    queue_ids = []

  clean_skill_ids = []
  clean_queue_ids = []
  for value in skill_ids:
    token = str(value or "").strip()
    if token and token not in clean_skill_ids:
      clean_skill_ids.append(token)
  for value in queue_ids:
    token = str(value or "").strip()
    if token and token not in clean_queue_ids:
      clean_queue_ids.append(token)

  enabled_value = str(enabled or "").strip().lower() in {"1", "true", "yes", "on"}
  payload = _load_genesys_division_filters()
  filters = payload.setdefault("filters", {}) if isinstance(payload, dict) else {}
  if not isinstance(filters, dict):
    filters = {}
    payload["filters"] = filters
  filters[clean_division_id] = {
    "division_id": clean_division_id,
    "filter_name": clean_filter_name,
    "division_name": clean_division_name,
    "skill_ids": clean_skill_ids,
    "queue_ids": clean_queue_ids,
    "enabled": enabled_value,
    "updated_at": datetime.datetime.now(datetime.timezone.utc).isoformat(),
  }

  if not _save_genesys_division_filters(payload):
    return JSONResponse({"ok": False, "error": "Unable to save division filter."}, status_code=500)

  return JSONResponse({
    "ok": True,
    "division_id": clean_division_id,
    "filter_name": clean_filter_name,
    "division_name": clean_division_name,
    "skill_ids": clean_skill_ids,
    "queue_ids": clean_queue_ids,
    "enabled": enabled_value,
    "path": GENESYS_DIVISION_FILTERS_PATH,
  })


@app.post("/genesys/division-filters/delete")
def genesys_division_filters_delete_route(
  division_id: str = Form(""),
):
  clean_division_id = str(division_id or "").strip()
  if not clean_division_id:
    return JSONResponse({"ok": False, "error": "division_id is required."}, status_code=400)

  payload = _load_genesys_division_filters()
  filters = payload.get("filters", {}) if isinstance(payload, dict) else {}
  if not isinstance(filters, dict):
    filters = {}
    payload["filters"] = filters

  if clean_division_id not in filters:
    return JSONResponse({"ok": False, "error": "Division filter not found."}, status_code=404)

  filters.pop(clean_division_id, None)
  if not _save_genesys_division_filters(payload):
    return JSONResponse({"ok": False, "error": "Unable to delete division filter."}, status_code=500)

  return JSONResponse({
    "ok": True,
    "division_id": clean_division_id,
    "path": GENESYS_DIVISION_FILTERS_PATH,
  })


@app.post("/genesys/users/search-update")
def genesys_user_search_update_route(
  user_email: str = Form(""),
  division_id: str = Form(""),
  skill_ids_json: str = Form("[]"),
  queue_ids_json: str = Form("[]"),
  update_division: str = Form("true"),
  update_skills: str = Form("true"),
  update_queues: str = Form("true"),
):
  def _to_bool(value: str, default: bool = False) -> bool:
    text = str(value or "").strip().lower()
    if not text:
      return default
    return text in {"1", "true", "yes", "on"}

  clean_region = (GENESYS_CLOUD_REGION or "usw2").strip().lower() or "usw2"
  clean_user_email = str(user_email or "").strip().lower()
  clean_division_id = str(division_id or "").strip()
  apply_division = _to_bool(update_division, True)
  apply_skills = _to_bool(update_skills, True)
  apply_queues = _to_bool(update_queues, True)

  if not clean_user_email or "@" not in clean_user_email:
    return JSONResponse({"ok": False, "error": "A valid user email is required."}, status_code=400)
  if not apply_division and not apply_skills and not apply_queues:
    return JSONResponse({"ok": False, "error": "At least one field update must be selected."}, status_code=400)

  try:
    skill_ids = json.loads(skill_ids_json or "[]")
  except Exception:
    skill_ids = []
  try:
    queue_ids = json.loads(queue_ids_json or "[]")
  except Exception:
    queue_ids = []

  if not isinstance(skill_ids, list):
    skill_ids = []
  if not isinstance(queue_ids, list):
    queue_ids = []

  # Defensive server-side inference for batch flow.
  if not apply_division and clean_division_id:
    apply_division = True
  if not apply_skills and any(str(item or "").strip() for item in skill_ids):
    apply_skills = True
  if not apply_queues and any(str(item or "").strip() for item in queue_ids):
    apply_queues = True

  token_result = _genesys_get_queue_access_token(clean_region)
  if not token_result.get("ok"):
    return JSONResponse({
      "ok": False,
      "error": token_result.get("error", "Genesys token request failed."),
    }, status_code=400)

  region = token_result.get("region", clean_region)
  access_token = token_result.get("access_token", "")

  user_lookup = _genesys_lookup_user_by_email(region, access_token, clean_user_email)
  if not user_lookup.get("ok"):
    return JSONResponse({
      "ok": False,
      "error": user_lookup.get("error", "Unable to find user by email."),
    }, status_code=400)

  prereq_result = _genesys_ensure_update_webrtc_prerequisite(
    region,
    access_token,
    user_lookup.get("user_id", ""),
    clean_user_email,
  )
  if not prereq_result.get("ok"):
    return JSONResponse({
      "ok": False,
      "error": prereq_result.get("error", "WebRTC prerequisite auto-heal failed."),
      "webrtc_phone": str(prereq_result.get("webrtc_phone", "") or "").strip(),
      "inventory_phone": str(prereq_result.get("inventory_phone", "") or "").strip(),
      "webrtc_status": str(prereq_result.get("webrtc_status", "") or "").strip(),
      "webrtc_create_mode": str(prereq_result.get("webrtc_create_mode", "") or "").strip(),
    }, status_code=400)

  apply_result = _genesys_apply_user_search_update(
    region,
    access_token,
    user_lookup.get("user_id", ""),
    clean_division_id,
    skill_ids,
    queue_ids,
    update_division=apply_division,
    update_skills=apply_skills,
    update_queues=apply_queues,
  )
  if not apply_result.get("ok"):
    return JSONResponse({
      "ok": False,
      "error": apply_result.get("error", "Update failed."),
    }, status_code=400)

  return JSONResponse({
    "ok": True,
    "region": region,
    "user_email": clean_user_email,
    "user_id": str(user_lookup.get("user_id", "") or "").strip(),
    "webrtc_status": str(prereq_result.get("webrtc_status", "already_associated") or "already_associated").strip(),
    "webrtc_phone": str(prereq_result.get("webrtc_phone", "") or "").strip(),
    "webrtc_create_mode": str(prereq_result.get("webrtc_create_mode", "existing") or "existing").strip(),
    "webrtc_warning": str(prereq_result.get("webrtc_warning", "") or "").strip(),
    "division_status": apply_result.get("division_status", ""),
    "skills_status": apply_result.get("skills_status", ""),
    "queues_status": apply_result.get("queues_status", ""),
  })


@app.post("/genesys/users/search-profile")
def genesys_user_search_profile_route(user_email: str = Form("")):
  clean_region = (GENESYS_CLOUD_REGION or "usw2").strip().lower() or "usw2"
  clean_user_email = str(user_email or "").strip().lower()
  if not clean_user_email or "@" not in clean_user_email:
    return JSONResponse({"ok": False, "error": "A valid user email is required."}, status_code=400)

  token_result = _genesys_get_queue_access_token(clean_region)
  if not token_result.get("ok"):
    return JSONResponse({
      "ok": False,
      "error": token_result.get("error", "Genesys token request failed."),
    }, status_code=400)

  region = token_result.get("region", clean_region)
  access_token = token_result.get("access_token", "")
  user_lookup = _genesys_lookup_user_by_email(region, access_token, clean_user_email)
  if not user_lookup.get("ok"):
    return JSONResponse({
      "ok": False,
      "error": user_lookup.get("error", "Unable to find user by email."),
    }, status_code=400)

  profile_result = _genesys_get_user_search_profile(
    region,
    access_token,
    user_lookup.get("user_id", ""),
    clean_user_email,
  )
  if not profile_result.get("ok"):
    return JSONResponse({"ok": False, "error": profile_result.get("error", "Profile lookup failed.")}, status_code=400)

  profile_result["lookup_email"] = clean_user_email

  return JSONResponse(profile_result)


@app.post("/genesys/users/search-update-batch")
def genesys_user_search_update_batch_route(
  users_json: str = Form("[]"),
  division_id: str = Form(""),
  skill_ids_json: str = Form("[]"),
  queue_ids_json: str = Form("[]"),
  update_division: str = Form("true"),
  update_skills: str = Form("true"),
  update_queues: str = Form("true"),
):
  def _to_bool(value: str, default: bool = False) -> bool:
    text = str(value or "").strip().lower()
    if not text:
      return default
    return text in {"1", "true", "yes", "on"}

  clean_region = (GENESYS_CLOUD_REGION or "usw2").strip().lower() or "usw2"
  clean_division_id = str(division_id or "").strip()
  apply_division = _to_bool(update_division, True)
  apply_skills = _to_bool(update_skills, True)
  apply_queues = _to_bool(update_queues, True)
  if not apply_division and not apply_skills and not apply_queues:
    return JSONResponse({"ok": False, "error": "At least one field update must be selected."}, status_code=400)

  try:
    parsed_users = json.loads(users_json or "[]")
  except Exception:
    return JSONResponse({"ok": False, "error": "users_json must be valid JSON."}, status_code=400)

  try:
    skill_ids = json.loads(skill_ids_json or "[]")
  except Exception:
    skill_ids = []
  try:
    queue_ids = json.loads(queue_ids_json or "[]")
  except Exception:
    queue_ids = []

  if not isinstance(skill_ids, list):
    skill_ids = []
  if not isinstance(queue_ids, list):
    queue_ids = []

  if not isinstance(parsed_users, list) or not parsed_users:
    return JSONResponse({"ok": False, "error": "At least one user is required."}, status_code=400)

  users = []
  seen = set()
  for row in parsed_users:
    if isinstance(row, dict):
      email = str(row.get("user_email", "") or "").strip().lower()
    else:
      email = str(row or "").strip().lower()
    if not email or "@" not in email or email in seen:
      continue
    seen.add(email)
    users.append(email)

  if not users:
    return JSONResponse({"ok": False, "error": "No valid user emails were provided."}, status_code=400)

  if len(users) > 100:
    return JSONResponse({"ok": False, "error": "Batch limit is 100 users per request."}, status_code=400)

  token_result = _genesys_get_queue_access_token(clean_region)
  if not token_result.get("ok"):
    return JSONResponse({
      "ok": False,
      "error": token_result.get("error", "Genesys token request failed."),
    }, status_code=400)

  region = token_result.get("region", clean_region)
  access_token = token_result.get("access_token", "")
  max_workers = 3
  started_at = time.time()

  def _run_one(index: int, email: str) -> tuple[int, dict]:
    try:
      user_lookup = _genesys_lookup_user_by_email(region, access_token, email)
      if not user_lookup.get("ok"):
        return index, {"ok": False, "user_email": email, "error": user_lookup.get("error", "User lookup failed.")}

      prereq_result = _genesys_ensure_update_webrtc_prerequisite(
        region,
        access_token,
        user_lookup.get("user_id", ""),
        email,
      )
      if not prereq_result.get("ok"):
        return index, {
          "ok": False,
          "user_email": email,
          "error": prereq_result.get("error", "WebRTC prerequisite auto-heal failed."),
          "webrtc_phone": str(prereq_result.get("webrtc_phone", "") or "").strip(),
          "inventory_phone": str(prereq_result.get("inventory_phone", "") or "").strip(),
          "webrtc_status": str(prereq_result.get("webrtc_status", "") or "").strip(),
          "webrtc_create_mode": str(prereq_result.get("webrtc_create_mode", "") or "").strip(),
        }

      apply_result = _genesys_apply_user_search_update(
        region,
        access_token,
        user_lookup.get("user_id", ""),
        clean_division_id,
        skill_ids,
        queue_ids,
        update_division=apply_division,
        update_skills=apply_skills,
        update_queues=apply_queues,
      )
      if not apply_result.get("ok"):
        return index, {"ok": False, "user_email": email, "error": apply_result.get("error", "Update failed.")}

      return index, {
        "ok": True,
        "user_email": email,
        "user_id": str(user_lookup.get("user_id", "") or "").strip(),
        "webrtc_status": str(prereq_result.get("webrtc_status", "already_associated") or "already_associated").strip(),
        "webrtc_phone": str(prereq_result.get("webrtc_phone", "") or "").strip(),
        "webrtc_create_mode": str(prereq_result.get("webrtc_create_mode", "existing") or "existing").strip(),
        "webrtc_warning": str(prereq_result.get("webrtc_warning", "") or "").strip(),
        "division_status": apply_result.get("division_status", ""),
        "skills_status": apply_result.get("skills_status", ""),
        "queues_status": apply_result.get("queues_status", ""),
      }
    except Exception as exc:
      return index, {"ok": False, "user_email": email, "error": f"Unhandled batch update error: {exc}"}

  indexed_results = [None] * len(users)
  with concurrent.futures.ThreadPoolExecutor(max_workers=max_workers) as executor:
    future_map = {executor.submit(_run_one, idx, email): idx for idx, email in enumerate(users)}
    for future in concurrent.futures.as_completed(future_map):
      idx, result = future.result()
      indexed_results[idx] = result

  results = [row for row in indexed_results if isinstance(row, dict)]
  success_count = sum(1 for row in results if row.get("ok"))
  failure_count = len(results) - success_count
  requested = len(users)
  status = "completed" if failure_count == 0 else "completed_with_failures"

  failed_emails = []
  seen_failed = set()
  for row in results:
    if row.get("ok"):
      continue
    email = str(row.get("user_email", "") or "").strip().lower()
    if not email or email in seen_failed:
      continue
    seen_failed.add(email)
    failed_emails.append(email)

  original_emails = list(users)
  timestamp_token = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
  original_text = "\n".join(original_emails) + ("\n" if original_emails else "")
  failed_text = "\n".join(failed_emails) + ("\n" if failed_emails else "")

  original_job_id = _store_job_output(
    original_text.encode("utf-8"),
    f"genesys_user_update_batch_original_{timestamp_token}.txt",
    "text/plain",
  )
  failed_job_id = _store_job_output(
    failed_text.encode("utf-8"),
    f"genesys_user_update_batch_failed_{timestamp_token}.txt",
    "text/plain",
  )
  original_download_url = f"/download/job-output/{original_job_id}"
  failed_download_url = f"/download/job-output/{failed_job_id}"

  applied_parts = []
  if apply_division:
    applied_parts.append("Division")
  if apply_skills:
    applied_parts.append(f"Skills({len(skill_ids)})")
  if apply_queues:
    applied_parts.append(f"Queues({len(queue_ids)})")
  applied_summary = ", ".join(applied_parts) if applied_parts else "(none)"

  duration_seconds = max(0.0, time.time() - started_at)
  _append_genesys_update_batch_history_event(
    status=status,
    requested=requested,
    success_count=success_count,
    failure_count=failure_count,
    workers=max_workers,
    duration_seconds=duration_seconds,
    applied_summary=applied_summary,
    original_emails=original_emails,
    failed_emails=failed_emails,
    original_download_url=original_download_url,
    failed_download_url=failed_download_url,
  )

  return JSONResponse({
    "ok": True,
    "region": region,
    "requested": requested,
    "workers": max_workers,
    "status": status,
    "duration_seconds": round(duration_seconds, 2),
    "success_count": success_count,
    "failure_count": failure_count,
    "original_emails": original_emails,
    "failed_emails": failed_emails,
    "original_emails_download_url": original_download_url,
    "failed_emails_download_url": failed_download_url,
    "results": results,
  })


@app.get("/genesys/users/search-update-history")
def genesys_user_search_update_history_route(limit: int = 20):
  rows = _read_genesys_update_batch_history(limit)
  return JSONResponse({"ok": True, "rows": rows})


@app.post("/login")
def login(
  cucm_host: str = Form(...),
  cucm_user: str = Form(...),
  cucm_pass: str = Form(...),
):
  ok, message = _validate_cucm_login(cucm_host.strip(), cucm_user.strip(), cucm_pass)
  if not ok:
    safe = escape(message)
    return HTMLResponse(
      f"""
<html><body style=\"font-family:Segoe UI,Arial,sans-serif;padding:24px;\">
  <h3>Login Failed</h3>
  <p>{safe}</p>
  <p><a href=\"/\">Back to Login</a></p>
</body></html>
""",
      status_code=401,
    )

  session_id = _create_auth_session(cucm_host, cucm_user, cucm_pass)
  response = RedirectResponse(url="/menu", status_code=303)
  response.set_cookie(
    key=SESSION_COOKIE_NAME,
    value=session_id,
    httponly=True,
    samesite="lax",
    secure=True,
    max_age=CREDENTIAL_CACHE_TTL_SECONDS,
  )
  return response


@app.get("/logout")
def logout(request: Request):
  session_id = request.cookies.get(SESSION_COOKIE_NAME, "")
  if session_id:
    AUTH_SESSIONS.pop(session_id, None)
    AUTH_SESSION_SECRETS.pop(session_id, None)

  response = RedirectResponse(url="/", status_code=303)
  response.delete_cookie(SESSION_COOKIE_NAME)
  return response


