@app.get("/sip-call-search", response_class=HTMLResponse)
def sip_call_search_page(request: Request):
  session = _get_auth_session(request) or {}
  session_username = str(session.get("username", ""))
  auth_cucm_host = str(session.get("cucm_host", "") or "")
  if not session_username:
    return HTMLResponse(content="<h3>401 Unauthorized</h3><p>Please log in first.</p>", status_code=401)

  if not _sip_call_search_available(auth_cucm_host):
    return HTMLResponse(
      content="<h3>404 Not Found</h3><p>The requested page is not available in this environment.</p>",
      status_code=404,
    )

  stats = _sip_capture_stats()
  env_text, env_css_class = _get_environment_label(auth_cucm_host)

  html = f"""
<html>
  <head>
    <title>SIP Call Search - Voice Operations Portal</title>
    <style>
      :root {{
        --amn-blue: #005eb8;
        --amn-navy: #002f6c;
        --amn-sky: #eaf4ff;
        --amn-ice: #f7fbff;
        --amn-text: #12304a;
        --amn-text-soft: #4e6a84;
        --amn-border: #c8dbee;
        --amn-shadow: 0 14px 30px rgba(0, 47, 108, 0.11);
      }}
      body {{ margin: 0; font-family: "Segoe UI", Tahoma, Arial, sans-serif; background: linear-gradient(180deg, #f7fbff 0%, #edf5fc 100%); color: var(--amn-text); }}
      .topbar {{
        display: flex;
        flex-wrap: nowrap;
        align-items: center;
        justify-content: space-between;
        gap: 10px;
        padding: 8px 12px;
        background:
          linear-gradient(120deg, rgba(0, 47, 108, 0.98), rgba(0, 94, 184, 0.94)),
          linear-gradient(90deg, var(--amn-navy), var(--amn-blue));
        color: #fff;
        box-shadow: 0 12px 28px rgba(0, 47, 108, 0.22);
        border-bottom: 1px solid rgba(255, 255, 255, 0.16);
      }}
      .topbar-brand {{ display: flex; align-items: center; gap: 10px; }}
      .brand-fallback {{ font-weight: 700; letter-spacing: 0.6px; text-transform: uppercase; font-size: 11px; opacity: 0.86; }}
      .topbar-right {{ display: flex; align-items: center; gap: 10px; min-width: 0; }}
      .topbar-mid {{ flex: 1 1 auto; display: flex; justify-content: center; min-width: 0; }}
      .topbar-nav {{ display: flex; align-items: center; gap: 10px; white-space: nowrap; }}
      .topbar a {{ color: #fff; text-decoration: none; font-weight: 700; margin-left: 0; }}
      .env-banner {{ display: inline-block; padding: 6px 10px; border-radius: 10px; border: 1px solid rgba(255,255,255,0.35); font-size: 11px; font-weight: 700; }}
      .topbar .env-banner {{ background: rgba(255, 255, 255, 0.12); color: #fff; border-color: rgba(255, 255, 255, 0.35); }}
      .topbar-btn {{
        display: inline-block;
        padding: 7px 12px;
        border-radius: 10px;
        font-size: 12px;
        font-weight: 700;
        text-decoration: none;
        border: 1px solid rgba(255, 255, 255, 0.65);
        transition: transform 0.18s ease, box-shadow 0.18s ease, background 0.18s ease;
      }}
      .topbar-btn-login {{ color: #fff; background: rgba(255, 255, 255, 0.1); backdrop-filter: blur(8px); }}
      .topbar-btn-logout {{ color: #fff; background: linear-gradient(180deg, #cb3b2f, #9f2018); border-color: #f0a79c; }}
      .topbar-btn:hover {{ transform: translateY(-1px); box-shadow: 0 8px 18px rgba(0, 0, 0, 0.16); }}
      .content {{ max-width: 1400px; margin: 0 auto; padding: 14px; }}
      .panel {{ background: rgba(255,255,255,0.96); border: 1px solid var(--amn-border); border-radius: 14px; box-shadow: var(--amn-shadow); }}
      .page-meta-label, .section-label {{ display: block; color: var(--amn-text-soft); font-size: 12px; text-transform: uppercase; letter-spacing: 0.04em; }}
      .topbar-stats {{ display: flex; align-items: center; justify-content: center; gap: 6px; margin-top: 0; }}
      .topbar-stat {{
        background: rgba(255,255,255,0.14);
        border: 1px solid rgba(255,255,255,0.26);
        border-radius: 10px;
        padding: 6px 10px;
        min-width: 170px;
        min-height: 32px;
        box-sizing: border-box;
        display: inline-flex;
        align-items: center;
        gap: 6px;
        line-height: 1.1;
      }}
      .topbar-stat .section-label {{ color: rgba(255,255,255,0.84); font-size: 10px; display: inline; margin: 0; }}
      .topbar-stat strong {{ display: inline; color: #ffffff; font-size: 13px; margin: 0; font-weight: 700; line-height: 1.1; white-space: nowrap; }}
      .panel {{ padding: 14px; margin-bottom: 14px; }}
      .search-grid {{ display: grid; grid-template-columns: repeat(3, minmax(0, 1fr)); gap: 10px; }}
      .search-grid input, .search-grid select {{ width: 100%; box-sizing: border-box; border: 1px solid var(--amn-border); border-radius: 8px; padding: 9px 10px; min-height: 38px; }}
      .search-grid input:focus, .search-grid select:focus {{ outline: none; border-color: var(--amn-blue); box-shadow: 0 0 0 4px rgba(0, 94, 184, 0.12); }}
      .search-grid .full {{ grid-column: 1 / -1; }}
      .actions {{ display: flex; gap: 10px; flex-wrap: wrap; margin-top: 12px; }}
      button {{ background: linear-gradient(180deg, #0c77d8, #005eb8); color: #fff; border: none; padding: 9px 14px; border-radius: 8px; font-weight: 700; cursor: pointer; box-shadow: 0 8px 18px rgba(0, 94, 184, 0.16); }}
      button:hover {{ filter: brightness(1.04); }}
      .muted {{ color: var(--amn-text-soft); font-size: 13px; line-height: 1.5; }}
      table {{ width: 100%; border-collapse: collapse; font-size: 13px; }}
      th, td {{ padding: 8px 10px; border-bottom: 1px solid var(--amn-border); vertical-align: top; }}
      thead tr {{ background: var(--amn-blue); color: #fff; }}
      tbody tr:nth-child(even) {{ background: var(--amn-ice); }}
      .sip-results-table {{ table-layout: auto; }}
      .sip-results-table th, .sip-results-table td {{ padding: 6px 6px; }}
      .sip-results-table th {{ white-space: nowrap; }}
      .sip-results-table .nowrap {{ white-space: nowrap; }}
      details summary {{ cursor: pointer; color: var(--amn-blue); font-weight: 700; }}
      code {{ font-family: Consolas, monospace; }}
      @media (max-width: 1450px) {{
        .topbar {{ flex-wrap: wrap; }}
        .topbar-mid {{ width: 100%; justify-content: flex-start; }}
        .topbar-right {{ width: 100%; justify-content: space-between; }}
      }}
      @media (max-width: 1100px) {{
        .topbar-mid {{ justify-content: stretch; }}
        .topbar-right {{ flex-direction: column; align-items: stretch; gap: 8px; }}
        .topbar-nav {{ flex-wrap: wrap; }}
        .topbar-stats {{ display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); }}
        .topbar-stat {{ min-width: 0; }}
        .search-grid {{ grid-template-columns: repeat(2, minmax(0, 1fr)); }}
      }}
      @media (max-width: 760px) {{ .topbar-stats, .search-grid {{ grid-template-columns: 1fr; }} }}
    </style>
  </head>
  <body>
    <header class="topbar">
      <div class="topbar-brand">
        <span class="brand-fallback">AMN Healthcare</span>
        <strong>Voice Operations Portal</strong>
      </div>
      <div class="topbar-mid">
        <section class="topbar-stats" id="sip-stats-grid">
          <div class="topbar-stat"><span class="section-label">Listener Status</span><strong id="sip-stat-enabled">Loading...</strong></div>
          <div class="topbar-stat"><span class="section-label">Total Stored</span><strong id="sip-stat-total">Loading...</strong></div>
          <div class="topbar-stat"><span class="section-label">Files</span><strong id="sip-stat-files">Loading...</strong></div>
        </section>
      </div>
      <div class="topbar-right">
        <div class="topbar-nav">
          <span class="env-banner {env_css_class}">{escape(env_text)}</span>
          <a class="topbar-btn topbar-btn-login" href="/menu">Main Operations</a>
          <a class="topbar-btn topbar-btn-login" href="/menu-admin">Administrative Items</a>
          <a class="topbar-btn topbar-btn-logout" href="/logout">Log Out</a>
        </div>
      </div>
    </header>
    <main class="content">
      <section class="panel">
        <h2 style="margin:0 0 10px 0;color:var(--amn-navy);">SIP Call Search - Search Filters</h2>
        <form id="sip-search-form">
          <div class="search-grid">
            <select name="source_key"><option value="">All Sources</option><option value="las-voip-rtr">Las Vegas CUBE</option><option value="las-ribbon-sbc">Las Vegas Ribbon SBC</option><option value="RNOVOIPRT01">Reno CUBE</option><option value="rno-ribbon-sbc">Reno Ribbon SBC</option></select>
            <input name="cisco_guid" placeholder="Cisco-GUID (recommended)">
            <input name="call_id" placeholder="Call-ID or phone number (optional)">
            <input name="method" placeholder="Method (INVITE, BYE, etc.)">
            <input name="response_code" placeholder="Response Code (200, 404, etc.)">
            <input name="from_digits" placeholder="From Digits">
            <input name="to_digits" placeholder="To Digits">
            <input name="query" class="full" placeholder="Search text across raw SIP debug lines and parsed fields">
            <input name="start_ts" type="datetime-local" placeholder="Start">
            <input name="end_ts" type="datetime-local" placeholder="End">
            <input name="limit" type="number" min="1" max="1000" value="200" placeholder="Limit">
            <label class="full muted" style="display:flex;align-items:center;gap:8px;">
              <input name="legacy_expand" type="checkbox" value="1" style="width:auto;min-height:auto;">
              Deep Legacy Parse (slower): reconstruct older line-based records into full SIP message blocks.
            </label>
          </div>
          <div class="actions">
            <button type="submit">Search SIP Records</button>
            <select id="sip-quick-start-minutes" title="Sets Start to now minus X minutes and End to now" style="border:1px solid var(--amn-border);border-radius:8px;padding:8px 10px;min-height:38px;">
              <option value="15" selected>Last 15 Minutes</option>
              <option value="10">Last 10 Minutes</option>
              <option value="5">Last 5 Minutes</option>
              <option value="30">Last 30 Minutes</option>
              <option value="60">Last 60 Minutes</option>
            </select>
            <button type="button" id="sip-apply-quick-start-btn" style="background:linear-gradient(180deg,#356a9c,#244e77);">Set Start to Recent</button>
            <button type="button" id="sip-build-ladder-btn" style="background:linear-gradient(180deg,#2f6c48,#1f5336);">Build SIP Ladder (Cisco-GUID / Call-ID)</button>
            <button type="button" id="sip-refresh-status-btn" style="background:linear-gradient(180deg,#516d8d,#355978);">Refresh Status</button>
          </div>
        </form>
        <p class="muted" id="sip-search-status" style="min-height:18px;">Ready. Normal filtered searches auto-reconstruct a small set of legacy rows; enable Deep Legacy Parse for broader legacy reconstruction. A digits-only value in the Call-ID box also searches caller/called numbers.</p>
        <div id="sip-search-results" style="overflow-x:auto;"></div>
        <p class="muted" id="sip-ladder-status" style="min-height:18px;margin-top:10px;">Cisco-GUID ladder diagram is generated on demand (Call-ID supported for compatibility).</p>
        <div id="sip-ladder-output" style="overflow-x:auto;"></div>
      </section>

      <section class="panel">
        <h2 style="margin:0 0 10px 0;color:var(--amn-navy);">Download Captured Files</h2>
        <div class="search-grid" style="margin-bottom:10px;">
          <input id="sip-files-start-ts" type="datetime-local" placeholder="Start">
          <input id="sip-files-end-ts" type="datetime-local" placeholder="End">
          <input id="sip-files-limit" type="number" min="1" max="300" value="5" placeholder="Limit">
        </div>
        <div class="actions">
          <button type="button" id="sip-refresh-files-btn" style="background:linear-gradient(180deg,#516d8d,#355978);">Refresh File List</button>
        </div>
        <p class="muted" id="sip-files-status" style="min-height:18px;">Loading recent capture files (last 5 by default)...</p>
        <div id="sip-files-list" style="overflow-x:auto;"></div>
      </section>
    </main>

    <script>
      (function () {{
        const stats = {json.dumps(stats, ensure_ascii=False)};
        const form = document.getElementById("sip-search-form");
        const resultsEl = document.getElementById("sip-search-results");
        const statusEl = document.getElementById("sip-search-status");
        const ladderStatusEl = document.getElementById("sip-ladder-status");
        const ladderOutputEl = document.getElementById("sip-ladder-output");
        const refreshBtn = document.getElementById("sip-refresh-status-btn");
        const refreshFilesBtn = document.getElementById("sip-refresh-files-btn");
        const ladderBtn = document.getElementById("sip-build-ladder-btn");
        const quickStartBtn = document.getElementById("sip-apply-quick-start-btn");
        const quickStartMinutesEl = document.getElementById("sip-quick-start-minutes");
        const enabledEl = document.getElementById("sip-stat-enabled");
        const totalEl = document.getElementById("sip-stat-total");
        const filesEl = document.getElementById("sip-stat-files");
        const filesStatusEl = document.getElementById("sip-files-status");
        const filesListEl = document.getElementById("sip-files-list");
        const filesStartTsEl = document.getElementById("sip-files-start-ts");
        const filesEndTsEl = document.getElementById("sip-files-end-ts");
        const filesLimitEl = document.getElementById("sip-files-limit");

        function escapeHtml(value) {{
          return String(value || "")
            .replace(/&/g, "&amp;")
            .replace(/</g, "&lt;")
            .replace(/>/g, "&gt;")
            .replace(/\"/g, "&quot;")
            .replace(/'/g, "&#39;");
        }}

        function humanBytes(bytes) {{
          const value = Number(bytes || 0);
          if (value >= 1024 * 1024 * 1024) return (value / (1024 * 1024 * 1024)).toFixed(2) + " GB";
          if (value >= 1024 * 1024) return (value / (1024 * 1024)).toFixed(2) + " MB";
          if (value >= 1024) return (value / 1024).toFixed(1) + " KB";
          return value + " B";
        }}

        function formatWhen(isoText) {{
          if (!isoText) return '';
          try {{
            return new Date(isoText).toLocaleString();
          }} catch (_err) {{
            return String(isoText || '');
          }}
        }}

        function formatReceivedTimestamp(value) {{
          const text = String(value || '').trim();
          if (!text) return '';
          const cleaned = text.replace(/([+-]\d{2}:\d{2}|Z)$/i, '');
          const m = cleaned.match(/^(\d{4}-\d{2}-\d{2})[T\s](\d{2}:\d{2}:\d{2}(?:\.\d+)?)/);
          if (m) return m[1] + ' ' + m[2];
          return cleaned.replace('T', ' ');
        }}

        function formatCiscoGuid(value) {{
          const text = String(value || '').trim();
          if (!text) return '';
          const parts = text.split('-');
          if (parts.length >= 4) {{
            return escapeHtml(parts.slice(0, 2).join('-')) + '<br>' + escapeHtml(parts.slice(2).join('-'));
          }}
          if (parts.length === 3) {{
            return escapeHtml(parts.slice(0, 2).join('-')) + '<br>' + escapeHtml(parts[2]);
          }}
          return escapeHtml(text);
        }}

        function formatCallId(value) {{
          const text = String(value || '').trim();
          if (!text) return '';
          const parts = text.split('-');
          if (parts.length >= 4) {{
            return escapeHtml(parts.slice(0, 2).join('-')) + '<br>' + escapeHtml(parts.slice(2).join('-'));
          }}
          if (parts.length === 3) {{
            return escapeHtml(parts.slice(0, 2).join('-')) + '<br>' + escapeHtml(parts[2]);
          }}
          return escapeHtml(text);
        }}

        function formatDirection(value) {{
          const text = String(value || '').trim();
          if (!text) return '';
          if (text.startsWith('Sent to ')) {{
            const endpoint = text.slice('Sent to '.length).trim();
            if (endpoint) return 'Sent to<br>' + escapeHtml(endpoint);
            return 'Sent to';
          }}
          if (text.startsWith('Received from ')) {{
            const endpoint = text.slice('Received from '.length).trim();
            if (endpoint) return 'Received from<br>' + escapeHtml(endpoint);
            return 'Received from';
          }}
          return escapeHtml(text);
        }}

        function toDatetimeLocalValue(dateObj) {{
          const yyyy = String(dateObj.getFullYear());
          const mm = String(dateObj.getMonth() + 1).padStart(2, '0');
          const dd = String(dateObj.getDate()).padStart(2, '0');
          const hh = String(dateObj.getHours()).padStart(2, '0');
          const mi = String(dateObj.getMinutes()).padStart(2, '0');
          return yyyy + '-' + mm + '-' + dd + 'T' + hh + ':' + mi;
        }}

        function normalizeDatetimeLocalForApi(value) {{
          const text = String(value || '').trim();
          if (!text) return '';
          const parsed = new Date(text);
          if (Number.isNaN(parsed.getTime())) return text;
          return parsed.toISOString();
        }}

        function setDefaultDateRange() {{
          if (!form) return;
          const startInput = form.querySelector('input[name="start_ts"]');
          const endInput = form.querySelector('input[name="end_ts"]');
          const now = new Date();
          const dayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0, 0, 0, 0);
          const dayEnd = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 23, 59, 0, 0);

          if (startInput && !String(startInput.value || '').trim()) {{
            startInput.value = toDatetimeLocalValue(dayStart);
          }}
          if (endInput && !String(endInput.value || '').trim()) {{
            endInput.value = toDatetimeLocalValue(dayEnd);
          }}
        }}

        async function parseJsonResponse(response, fallbackMessage) {{
          const rawText = await response.text();
          let payload;
          try {{
            payload = JSON.parse(rawText || '{{}}');
          }} catch (_err) {{
            const snippet = String(rawText || '').slice(0, 220);
            throw new Error((fallbackMessage || 'Unexpected response format') + ': ' + (snippet || 'empty response'));
          }}
          if (!response.ok || !payload.ok) {{
            throw new Error((payload && payload.error) || fallbackMessage || 'Request failed');
          }}
          return payload;
        }}

        function renderStats(payload) {{
          const s = (payload && payload.stats) || stats || {{}};
          enabledEl.textContent = s.enabled ? ("Listening on UDP " + s.udp_port) : "Disabled";
          totalEl.textContent = humanBytes(s.total_bytes || 0) + " / " + (s.total_mb || 0) + " MB cap";
          filesEl.textContent = String(s.file_count || 0);
        }}

        function renderResults(rows) {{
          if (!rows || !rows.length) {{
            resultsEl.innerHTML = '<div class="panel"><p class="muted" style="margin:0;">No SIP records matched the current filters.</p></div>';
            return;
          }}
          let html = '<table class="sip-results-table"><colgroup>'
            + '<col style="width:180px">'
            + '<col style="width:110px">'
            + '<col style="width:140px">'
            + '<col style="width:65px">'
            + '<col style="width:70px">'
            + '<col style="width:88px">'
            + '<col style="width:88px">'
            + '<col>'
            + '<col style="width:170px">'
            + '<col style="width:150px">'
            + '<col style="width:190px">'
            + '<col style="width:150px">'
            + '</colgroup><thead><tr><th>Received</th><th>Source</th><th>Direction</th><th>Method</th><th>Response</th><th>From</th><th>To</th><th>Raw</th><th>Cisco-GUID</th><th>Call-ID</th><th>Call Group ID</th><th>Capture File</th></tr></thead><tbody>';
          rows.forEach(function (row, idx) {{
            const bg = idx % 2 === 0 ? '#f7fbff' : '#ffffff';
            const captureFile = (row.raw_file_rel || row.index_file_rel || '').toString();
            const captureLink = captureFile ? ('/sip-call-search/download?rel_path=' + encodeURIComponent(captureFile)) : '';
            const captureName = captureFile ? captureFile.split('/').pop() : '';
            const captureCell = captureLink
              ? ('<a href="' + captureLink + '" title="' + escapeHtml(captureFile) + '" style="font-weight:700;color:#005eb8;">' + escapeHtml(captureName) + '</a>')
              : '<span class="muted">(legacy record - file not resolved)</span>';
            html += '<tr style="background:' + bg + ';">'
              + '<td class="nowrap">' + escapeHtml(row.received_at_display || formatReceivedTimestamp(row.received_at || '')) + '</td>'
              + '<td><strong>' + escapeHtml(row.source_label || row.source_key || '') + '</strong><br><span class="muted">' + escapeHtml(row.source_ip || '') + '</span></td>'
              + '<td style="white-space:normal;line-height:1.2;">' + formatDirection(row.direction_detail || row.direction || '') + '</td>'
              + '<td class="nowrap">' + escapeHtml(row.method || '') + '</td>'
              + '<td class="nowrap">' + escapeHtml(row.response_code || '') + '</td>'
              + '<td class="nowrap" style="font-family:Consolas,monospace;">' + escapeHtml(row.from_digits || row.from_value || '') + '</td>'
              + '<td class="nowrap" style="font-family:Consolas,monospace;">' + escapeHtml(row.to_digits || row.to_value || '') + '</td>'
              + '<td><details><summary>Show</summary><div style="margin-top:6px;font-family:Consolas,monospace;white-space:pre-wrap;max-width:1000px;">' + escapeHtml(row.raw_message || row.raw_line || '') + '</div></details></td>'
              + '<td style="font-family:Consolas,monospace;white-space:normal;line-height:1.25;">' + formatCiscoGuid(row.cisco_guid || '') + '</td>'
              + '<td style="font-family:Consolas,monospace;white-space:normal;line-height:1.25;">' + formatCallId(row.call_id || '') + '</td>'
                + '<td style="font-family:Consolas,monospace;white-space:normal;line-height:1.2;">' + escapeHtml(row.call_group_id || '') + '</td>'
              + '<td style="font-family:Consolas,monospace;max-width:340px;word-break:break-word;">' + captureCell + '</td>'
              + '</tr>';
          }});
          html += '</tbody></table>';
          resultsEl.innerHTML = html;
        }}

        function renderFiles(rows) {{
          if (!filesListEl) return;
          if (!rows || !rows.length) {{
            filesListEl.innerHTML = '<div class="panel"><p class="muted" style="margin:0;">No capture files found yet.</p></div>';
            return;
          }}
          let html = '<table><thead><tr><th>Type</th><th>File</th><th>Size</th><th>Modified</th><th>Download</th></tr></thead><tbody>';
          rows.forEach(function (row, idx) {{
            const bg = idx % 2 === 0 ? '#f7fbff' : '#ffffff';
            const relPath = String((row && row.rel_path) || '');
            const href = '/sip-call-search/download?rel_path=' + encodeURIComponent(relPath);
            html += '<tr style="background:' + bg + ';">'
              + '<td>' + escapeHtml(row.kind || '') + '</td>'
              + '<td style="font-family:Consolas,monospace;">' + escapeHtml(relPath) + '</td>'
              + '<td>' + escapeHtml(humanBytes(row.size_bytes || 0)) + '</td>'
              + '<td>' + escapeHtml(formatWhen(row.modified_at || '')) + '</td>'
              + '<td><a href="' + href + '" style="font-weight:700;color:#005eb8;">Download</a></td>'
              + '</tr>';
          }});
          html += '</tbody></table>';
          filesListEl.innerHTML = html;
        }}

        function renderLadder(payload) {{
          if (!ladderOutputEl) return;
          const participants = (payload && payload.participants) || [];
          const events = (payload && payload.events) || [];
          const mermaidText = String((payload && payload.mermaid) || '').trim();
          if (!participants.length || !events.length) {{
            if (!mermaidText) {{
              ladderOutputEl.innerHTML = '';
              return;
            }}
          }}
          if (!participants.length || !events.length) {{
            ladderOutputEl.innerHTML = '<div class="panel" style="margin-top:10px;"><h3 style="margin:0 0 8px 0;color:#002f6c;">SIP Ladder (Mermaid)</h3><pre style="margin:0;font-family:Consolas,monospace;white-space:pre;overflow:auto;max-height:520px;">' + escapeHtml(mermaidText) + '</pre></div>';
            return;
          }}

          const topPad = 64;
          const bottomPad = 36;
          const leftPad = 56;
          const rightPad = 56;
          const rowHeight = 46;
          const width = Math.max(760, leftPad + rightPad + ((participants.length - 1) * 220) + 60);
          const height = topPad + bottomPad + (events.length * rowHeight);
          const availableWidth = width - leftPad - rightPad;
          const xStep = participants.length > 1 ? (availableWidth / (participants.length - 1)) : 0;
          const lifelineBottom = height - bottomPad;
          const markerId = 'sip-arrowhead';

          function svgEscape(value) {{
            return String(value || '')
              .replace(/&/g, '&amp;')
              .replace(/</g, '&lt;')
              .replace(/>/g, '&gt;')
              .replace(/"/g, '&quot;')
              .replace(/'/g, '&apos;');
          }}

          const participantX = participants.map(function (_item, idx) {{
            return leftPad + (idx * xStep);
          }});

          let svg = '';
          svg += '<svg xmlns="http://www.w3.org/2000/svg" width="' + width + '" height="' + height + '" viewBox="0 0 ' + width + ' ' + height + '" role="img" aria-label="SIP ladder diagram">';
          svg += '<defs><marker id="' + markerId + '" markerWidth="10" markerHeight="8" refX="9" refY="4" orient="auto" markerUnits="strokeWidth"><path d="M0,0 L10,4 L0,8 z" fill="#0b4f9c"></path></marker></defs>';
          svg += '<rect x="0" y="0" width="' + width + '" height="' + height + '" rx="14" ry="14" fill="#ffffff" stroke="#c8dbee"/>';

          participants.forEach(function (participant, idx) {{
            const x = participantX[idx];
            svg += '<text x="' + x + '" y="26" text-anchor="middle" font-family="Segoe UI, Tahoma, Arial, sans-serif" font-size="16" font-weight="700" fill="#002f6c">' + svgEscape(participant.label || ('Peer ' + (idx + 1))) + '</text>';
            svg += '<line x1="' + x + '" y1="42" x2="' + x + '" y2="' + lifelineBottom + '" stroke="#8aa7c4" stroke-width="1.5" stroke-dasharray="6 6"/>';
          }});

          events.forEach(function (event, idx) {{
            const fromIndex = Number(event.from_index || 0);
            const toIndex = Number(event.to_index || 0);
            const x1 = participantX[fromIndex] || leftPad;
            const x2 = participantX[toIndex] || leftPad;
            const y = topPad + (idx * rowHeight);
            const label = String(event.label || 'SIP');
            const timeText = String(event.time || '').trim();
            const midX = (x1 + x2) / 2;
            svg += '<line x1="' + x1 + '" y1="' + y + '" x2="' + x2 + '" y2="' + y + '" stroke="#0b4f9c" stroke-width="2" marker-end="url(#' + markerId + ')"/>';
            svg += '<text x="' + midX + '" y="' + (y - 10) + '" text-anchor="middle" font-family="Segoe UI, Tahoma, Arial, sans-serif" font-size="15" font-weight="700" fill="#143a63">' + svgEscape(label) + '</text>';
            if (timeText) {{
              svg += '<text x="' + midX + '" y="' + (y + 15) + '" text-anchor="middle" font-family="Segoe UI, Tahoma, Arial, sans-serif" font-size="11" fill="#5b7894">' + svgEscape(timeText) + '</text>';
            }}
          }});

          svg += '</svg>';
          let html = '<div class="panel" style="margin-top:10px;">';
          html += '<h3 style="margin:0 0 10px 0;color:#002f6c;">SIP Ladder</h3>';
          html += '<div style="overflow:auto;">' + svg + '</div>';
          if (mermaidText) {{
            html += '<details style="margin-top:10px;"><summary style="font-weight:700;color:#005eb8;cursor:pointer;">Show Mermaid source</summary><pre style="margin:8px 0 0 0;font-family:Consolas,monospace;white-space:pre;overflow:auto;max-height:320px;">' + escapeHtml(mermaidText) + '</pre></details>';
          }}
          html += '</div>';
          ladderOutputEl.innerHTML = html;
        }}

        async function refreshStatus() {{
          try {{
            const response = await fetch('/sip-call-search/status', {{ credentials: 'same-origin' }});
            const payload = await parseJsonResponse(response, 'Status lookup failed');
            renderStats(payload);
          }} catch (err) {{
            enabledEl.textContent = 'Status unavailable';
          }}
        }}

        async function runSearch(event) {{
          if (event) event.preventDefault();
          statusEl.textContent = 'Searching SIP records...';
          resultsEl.innerHTML = '';
          try {{
            const fd = new FormData(form);
            const body = {{}};
            fd.forEach(function (value, key) {{
              const text = String(value || '').trim();
              body[key] = (key === 'start_ts' || key === 'end_ts') ? normalizeDatetimeLocalForApi(text) : text;
            }});
            const response = await fetch('/sip-call-search/search', {{
              method: 'POST',
              headers: {{ 'Content-Type': 'application/json' }},
              body: JSON.stringify(body),
              credentials: 'same-origin',
            }});
            const payload = await parseJsonResponse(response, 'Search failed');
            statusEl.textContent = 'Matched ' + (payload.count || 0) + ' record(s).';
            renderResults(payload.results || []);
            renderStats(payload);
          }} catch (err) {{
            statusEl.textContent = 'Search failed: ' + ((err && err.message) || 'Unknown error.');
          }}
        }}

        function setRecentStartTime() {{
          if (!form) return;
          const startInput = form.querySelector('input[name="start_ts"]');
          const endInput = form.querySelector('input[name="end_ts"]');
          const minutesRaw = String((quickStartMinutesEl && quickStartMinutesEl.value) || '15').trim();
          const minutes = Math.max(1, Math.min(240, Number(minutesRaw) || 10));
          const now = new Date();
          const start = new Date(now.getTime() - (minutes * 60 * 1000));
          if (startInput) startInput.value = toDatetimeLocalValue(start);
          if (endInput) endInput.value = toDatetimeLocalValue(now);
          statusEl.textContent = 'Start/End set to last ' + minutes + ' minute(s). Click Search SIP Records to run.';
        }}

        async function refreshFiles() {{
          if (!filesStatusEl) return;
          filesStatusEl.textContent = 'Loading capture files...';
          try {{
            const params = new URLSearchParams();
            const limitValue = String((filesLimitEl && filesLimitEl.value) || '5').trim();
            const startValue = normalizeDatetimeLocalForApi(String((filesStartTsEl && filesStartTsEl.value) || '').trim());
            const endValue = normalizeDatetimeLocalForApi(String((filesEndTsEl && filesEndTsEl.value) || '').trim());
            params.set('limit', limitValue || '5');
            if (startValue) params.set('start_ts', startValue);
            if (endValue) params.set('end_ts', endValue);

            const response = await fetch('/sip-call-search/files?' + params.toString(), {{ credentials: 'same-origin' }});
            const payload = await parseJsonResponse(response, 'File list lookup failed');
            const rows = payload.files || [];
            filesStatusEl.textContent = 'Showing ' + rows.length + ' capture file(s).';
            renderFiles(rows);
          }} catch (err) {{
            filesStatusEl.textContent = 'File list failed: ' + ((err && err.message) || 'Unknown error.');
          }}
        }}

        async function buildLadder() {{
          if (!form || !ladderStatusEl) return;
          const fd = new FormData(form);
          const body = {{}};
          fd.forEach(function (value, key) {{ body[key] = String(value || '').trim(); }});
          const hasCiscoGuid = String(body.cisco_guid || '').trim().length > 0;
          const hasCallId = String(body.call_id || '').trim().length > 0;
          if (!hasCiscoGuid && !hasCallId) {{
            ladderStatusEl.textContent = 'Build SIP Ladder requires Cisco-GUID or Call-ID.';
            renderLadder(null);
            return;
          }}
          ladderStatusEl.textContent = 'Building SIP ladder...';
          renderLadder(null);
          try {{
            const response = await fetch('/sip-call-search/ladder', {{
              method: 'POST',
              headers: {{ 'Content-Type': 'application/json' }},
              body: JSON.stringify(body),
              credentials: 'same-origin',
            }});
            const payload = await parseJsonResponse(response, 'Ladder build failed');
            ladderStatusEl.textContent = 'Built ladder with ' + (payload.event_count || 0) + ' event(s).';
            renderLadder(payload);
          }} catch (err) {{
            ladderStatusEl.textContent = 'Ladder build failed: ' + ((err && err.message) || 'Unknown error.');
          }}
        }}

        if (form) form.addEventListener('submit', runSearch);
        if (quickStartBtn) quickStartBtn.addEventListener('click', setRecentStartTime);
        if (refreshBtn) refreshBtn.addEventListener('click', refreshStatus);
        if (refreshFilesBtn) refreshFilesBtn.addEventListener('click', refreshFiles);
        if (ladderBtn) ladderBtn.addEventListener('click', buildLadder);
        setDefaultDateRange();
        renderStats({{ stats: stats }});
        refreshStatus();
        refreshFiles();
      }})();
    </script>
  </body>
</html>
"""

  return HTMLResponse(content=html)


@app.get("/sip-call-search/status")
def sip_call_search_status(request: Request):
  session = _get_auth_session(request)
  if not session:
    return JSONResponse({"ok": False, "error": "Authentication required"}, status_code=401)

  auth_cucm_host = str(session.get("cucm_host", "") or "")
  if not _sip_call_search_available(auth_cucm_host):
    return JSONResponse({"ok": False, "error": "Not found"}, status_code=404)

  return JSONResponse({"ok": True, "stats": _sip_capture_stats()})


@app.post("/sip-call-search/search")
async def sip_call_search_search(request: Request):
  session = _get_auth_session(request)
  if not session:
    return JSONResponse({"ok": False, "error": "Authentication required"}, status_code=401)

  auth_cucm_host = str(session.get("cucm_host", "") or "")
  if not _sip_call_search_available(auth_cucm_host):
    return JSONResponse({"ok": False, "error": "Not found"}, status_code=404)

  try:
    body = await request.json()
  except Exception:
    body = {}

  if not isinstance(body, dict):
    body = {}

  try:
    records = _sip_capture_records_for_search(body)
    return JSONResponse({"ok": True, "count": len(records), "results": records, "stats": _sip_capture_stats()})
  except Exception as exc:
    logger.error("SIP call-search query failed: %s", exc, exc_info=True)
    return JSONResponse({"ok": False, "error": f"Search backend error: {exc}"}, status_code=500)


@app.post("/sip-call-search/ladder")
async def sip_call_search_ladder(request: Request):
  session = _get_auth_session(request)
  if not session:
    return JSONResponse({"ok": False, "error": "Authentication required"}, status_code=401)

  auth_cucm_host = str(session.get("cucm_host", "") or "")
  if not _sip_call_search_available(auth_cucm_host):
    return JSONResponse({"ok": False, "error": "Not found"}, status_code=404)

  try:
    body = await request.json()
  except Exception:
    body = {}

  if not isinstance(body, dict):
    body = {}

  try:
    mermaid, event_count, participants, events = _sip_build_ladder_mermaid(body)
    return JSONResponse({"ok": True, "event_count": event_count, "mermaid": mermaid, "participants": participants, "events": events})
  except ValueError as exc:
    return JSONResponse({"ok": False, "error": str(exc)}, status_code=400)
  except Exception as exc:
    logger.error("SIP ladder build failed: %s", exc, exc_info=True)
    return JSONResponse({"ok": False, "error": f"Ladder backend error: {exc}"}, status_code=500)


@app.get("/sip-call-search/files")
def sip_call_search_files(
  request: Request,
  limit: int = Query(5),
  start_ts: str = Query(""),
  end_ts: str = Query(""),
):
  session = _get_auth_session(request)
  if not session:
    return JSONResponse({"ok": False, "error": "Authentication required"}, status_code=401)

  auth_cucm_host = str(session.get("cucm_host", "") or "")
  if not _sip_call_search_available(auth_cucm_host):
    return JSONResponse({"ok": False, "error": "Not found"}, status_code=404)

  files = _sip_list_capture_files(limit=limit, start_ts=start_ts, end_ts=end_ts)
  return JSONResponse({"ok": True, "files": files})


@app.get("/sip-call-search/download")
def sip_call_search_download(request: Request, rel_path: str = Query("")):
  session = _get_auth_session(request)
  if not session:
    return JSONResponse({"ok": False, "error": "Authentication required"}, status_code=401)

  auth_cucm_host = str(session.get("cucm_host", "") or "")
  if not _sip_call_search_available(auth_cucm_host):
    return JSONResponse({"ok": False, "error": "Not found"}, status_code=404)

  file_path = _sip_resolve_download_path(rel_path)
  if not file_path:
    return JSONResponse({"ok": False, "error": "File not found"}, status_code=404)

  try:
    with open(file_path, "rb") as handle:
      data = handle.read()
  except OSError:
    return JSONResponse({"ok": False, "error": "File read failed"}, status_code=500)

  filename = os.path.basename(file_path)
  media_type = "application/octet-stream"
  lower_name = filename.lower()
  if lower_name.endswith(".log"):
    media_type = "text/plain"
  elif lower_name.endswith(".jsonl"):
    media_type = "application/x-ndjson"

  return Response(
    data,
    media_type=media_type,
    headers={"Content-Disposition": f'attachment; filename="{filename}"'},
  )


