@app.get("/api/dashboard/stats")
def api_dashboard_stats(request: Request):
  warnings = []
  pull_mode = "full"

  # Dashboard must use the DN report service credentials (ucmappadmin),
  # not the interactive operator credentials.
  dn_cfg = _get_dn_report_settings()
  resolved_cucm_host = PROD_CUCM_HOST
  resolved_cucm_user = "ucmappadmin"
  resolved_cucm_pass = (dn_cfg.get("cucm_pass", "") or "").strip()

  if not resolved_cucm_host:
    return JSONResponse({"ok": False, "error": "Dashboard CUCM host is missing."}, status_code=400)
  if not resolved_cucm_user or not resolved_cucm_pass:
    return JSONResponse({"ok": False, "error": "Dashboard service credentials are missing. Configure DN report CUCM user/password in settings."}, status_code=400)

  configured_by_prefix = {"CSF": 0, "TCT": 0, "BOT": 0, "SEP": 0}
  registered_by_prefix = {"CSF": 0, "TCT": 0, "BOT": 0, "SEP": 0}
  by_server_registered = []
  active_calls = None
  jabber_active_calls = None
  ris_available = True
  jabber_registered_total = 0
  trunk_activity = {
    "ribbon_active_calls": 0,
    "cube_active_calls": 0,
    "other_active_calls": 0,
    "ribbon_ips": list(RIBBON_SBC_IPS),
    "cube_ips": list(CUBE_IPS),
  }

  with concurrent.futures.ThreadPoolExecutor(max_workers=4) as pool:
    future_map = {
      pool.submit(
        _axl_count_phones_by_prefix,
        resolved_cucm_host,
        resolved_cucm_user,
        resolved_cucm_pass,
        prefix,
      ): prefix
      for prefix in list(configured_by_prefix.keys())
    }
    for future in concurrent.futures.as_completed(future_map):
      prefix = future_map[future]
      try:
        configured_by_prefix[prefix] = int(future.result())
      except Exception as exc:
        warnings.append(str(exc))

  try:
    ris = _ris_fetch_jabber_registrations(
      resolved_cucm_host,
      resolved_cucm_user,
      resolved_cucm_pass,
    )
    registered_by_prefix = ris.get("by_prefix_registered", registered_by_prefix)
    jabber_registered_total = int(ris.get("registered_total", sum(registered_by_prefix.values())) or 0)
    active_calls = ris.get("active_calls")
    if active_calls is not None:
      jabber_active_calls = int(active_calls or 0)
    by_server_map = ris.get("by_server_registered", {}) or {}
    by_server_registered = [
      {"server": server_name, "registered": count}
      for server_name, count in sorted(by_server_map.items(), key=lambda item: item[0].lower())
    ]
  except Exception as exc:
    ris_available = False
    ris_err = str(exc)
    if "No target service to authorize for" in ris_err:
      warnings.append(f"Realtime RIS data is not authorized for dashboard service account '{resolved_cucm_user}'. Configure RIS/serviceability permissions to enable registered-device and active-call metrics.")
    elif "endpoint reference (EPR)" in ris_err:
      warnings.append("Realtime RIS endpoint is not available on this CUCM service path. Registered-device and active-call metrics are temporarily unavailable.")
    else:
      warnings.append(f"Realtime RIS data unavailable: {ris_err}")

    try:
      perf = _perfmon_registered_fallback(resolved_cucm_host, resolved_cucm_user, resolved_cucm_pass)
      perf_map = perf.get("by_server_registered", {}) or {}
      if perf_map:
        by_server_registered = [
          {"server": server_name, "registered": count}
          for server_name, count in sorted(perf_map.items(), key=lambda item: item[0].lower())
        ]
        jabber_registered_total = int(perf.get("registered_total", 0) or 0)
        # RIS is unavailable in this cluster context; estimate prefix split by
        # configured-device proportions so the prefix table is still useful.
        cfg_total = sum(int(v or 0) for v in configured_by_prefix.values())
        if cfg_total > 0 and jabber_registered_total > 0:
          estimated = {}
          remainders = []
          assigned = 0
          for prefix in ["CSF", "TCT", "BOT", "SEP"]:
            configured_count = int(configured_by_prefix.get(prefix, 0) or 0)
            exact = (jabber_registered_total * configured_count) / cfg_total
            base = int(exact)
            estimated[prefix] = base
            assigned += base
            remainders.append((exact - base, prefix))

          remaining = jabber_registered_total - assigned
          for _, prefix in sorted(remainders, key=lambda item: item[0], reverse=True)[:max(0, remaining)]:
            estimated[prefix] = int(estimated.get(prefix, 0)) + 1

          registered_by_prefix = estimated
        warnings.append("Using PerfMon fallback for registered-device totals because RIS realtime access is unavailable.")
      elif perf.get("errors"):
        warnings.append("PerfMon fallback unavailable: " + " | ".join(perf.get("errors", [])))
    except Exception as perf_exc:
      warnings.append(f"PerfMon fallback unavailable: {perf_exc}")

  if active_calls is None:
    try:
      perf_calls = _perfmon_active_calls_fallback(resolved_cucm_host, resolved_cucm_user, resolved_cucm_pass)
      if perf_calls.get("active_calls_total") is not None:
        active_calls = int(perf_calls.get("active_calls_total") or 0)
        warnings.append("Using PerfMon fallback for active-call total because RIS realtime active-call metric is unavailable.")
      elif ris_available:
        warnings.append("Active-call total unavailable from both RIS and PerfMon in this cluster context.")
    except Exception as perf_call_exc:
      warnings.append(f"Active-call fallback unavailable: {perf_call_exc}")

  if ris_available and active_calls is None:
    warnings.append("Realtime active-call counter not returned by this CUCM response; showing N/A.")

  try:
    trunk_activity = _perfmon_trunk_activity_fallback(resolved_cucm_host, resolved_cucm_user, resolved_cucm_pass)
    if trunk_activity.get("errors"):
      warnings.append("SIP trunk activity partial data: " + " | ".join(trunk_activity.get("errors", [])))
  except Exception as trunk_exc:
    warnings.append(f"SIP trunk activity unavailable: {trunk_exc}")

  ribbon_calls = int(trunk_activity.get("ribbon_active_calls", 0) or 0)
  cube_calls = int(trunk_activity.get("cube_active_calls", 0) or 0)
  other_trunk_calls = int(trunk_activity.get("other_active_calls", 0) or 0)
  cm_rows = [
    row
    for row in list(trunk_activity.get("all_call_related_counters", []) or [])
    if str((row or {}).get("object", "") or "").strip().lower() == "cisco callmanager"
  ]
  callmanager_calls_active = _aggregate_callmanager_counter_values(cm_rows, "CallsActive")
  callmanager_registered_devices_mra = _aggregate_callmanager_counter_values(cm_rows, "RegisteredDevicesMRA")

  mra_host_set = set()
  for row in cm_rows:
    counter_name = str((row or {}).get("counter", "") or "").strip().lower()
    if not (counter_name.endswith("\\registeredcsfjabbermra") or counter_name.endswith("\\registereddevicesmra")):
      continue
    try:
      if int((row or {}).get("value", 0) or 0) > 0:
        mra_host_set.add(str((row or {}).get("host", "") or "").strip().lower())
    except Exception:
      continue

  callmanager_calls_active_on_mra_hosts = 0
  for row in cm_rows:
    host = str((row or {}).get("host", "") or "").strip().lower()
    counter_name = str((row or {}).get("counter", "") or "").strip().lower()
    if host not in mra_host_set:
      continue
    if not counter_name.endswith("\\callsactive"):
      continue
    try:
      callmanager_calls_active_on_mra_hosts += int((row or {}).get("value", 0) or 0)
    except Exception:
      continue
  # CUBE and Ribbon can represent the same call path for contact-center calls;
  # avoid summing them directly when estimating endpoint calls.
  trunk_dominant_calls = max(ribbon_calls, cube_calls, other_trunk_calls)
  pstn_via_cube_calls = int(cube_calls or 0)

  jabber_calls_source = "ris"
  cluster_total_calls = int(active_calls or 0) if active_calls is not None else 0
  if jabber_active_calls is None:
    jabber_calls_source = "estimate_total_minus_dominant_trunk"
    jabber_active_calls = max(0, cluster_total_calls - trunk_dominant_calls)

  if cluster_total_calls > 0:
    total_active_calls = cluster_total_calls
  else:
    total_active_calls = int(jabber_active_calls or 0) + trunk_dominant_calls
  active_calls = total_active_calls

  call_activity = {
    "pstn_via_cube_active_calls": pstn_via_cube_calls,
    "callmanager_calls_active": callmanager_calls_active,
    "callmanager_calls_active_on_mra_hosts": callmanager_calls_active_on_mra_hosts,
    "callmanager_registered_devices_mra": callmanager_registered_devices_mra,
    "callmanager_mra_hosts_used": sorted(list(mra_host_set)),
    "ribbon_active_calls": ribbon_calls,
    "cube_active_calls": cube_calls,
    "jabber_active_calls": int(jabber_active_calls or 0),
    "other_trunk_active_calls": other_trunk_calls,
    "total_active_calls": total_active_calls,
    "all_call_related_counters": list(trunk_activity.get("all_call_related_counters", []) or []),
    "counter_collection_errors": list(trunk_activity.get("counter_collection_errors", []) or []),
    "jabber_calls_source": jabber_calls_source,
  }

  return JSONResponse(
    {
      "ok": True,
      "mode": pull_mode,
      "generated_at": datetime.datetime.now().strftime(AUDIT_TIMESTAMP_FORMAT),
      "environment": "LAB" if _is_lab_environment(resolved_cucm_host) else "PROD",
      "cucm_host": resolved_cucm_host,
      "stats": {
        "configured_by_prefix": configured_by_prefix,
        "registered_by_prefix": registered_by_prefix,
        "jabber_csf_configured_total": int(configured_by_prefix.get("CSF", 0) or 0),
        "jabber_csf_registered_total": int(registered_by_prefix.get("CSF", 0) or 0),
        "jabber_configured_total": sum(configured_by_prefix.values()),
        "jabber_registered_total": jabber_registered_total,
        "registered_by_server": by_server_registered,
        "active_calls": active_calls,
        "trunk_activity": trunk_activity,
        "call_activity": call_activity,
      },
      "warnings": warnings,
    }
  )


@app.get("/dashboard.js")
def dashboard_script():
  js = """
(function () {
  const intervalSelect = document.getElementById("refreshInterval");
  const autoRefreshCb = document.getElementById("autoRefresh");
  const refreshBtn = document.getElementById("refreshNow");
  const lastRefreshEl = document.getElementById("lastRefresh");
  const kpiActiveCalls = document.getElementById("kpiActiveCalls");
  const kpiConfigured = document.getElementById("kpiConfigured");
  const kpiRegistered = document.getElementById("kpiRegistered");
  const callMgrCallsActiveMraHosts = document.getElementById("callMgrCallsActiveMraHosts");
  const callJabber = document.getElementById("callJabber");
  const callTotal = document.getElementById("callTotal");
  const prefixRows = document.getElementById("prefixRows");
  

  if (!refreshBtn || !intervalSelect || !autoRefreshCb || !prefixRows) {
    return;
  }

  let timerId = null;

  function renderErrorRows(message) {
    const text = String(message || "Dashboard request failed");
    prefixRows.innerHTML = '<tr><td colspan="3" class="bad">' + text + '</td></tr>';
    if (kpiActiveCalls) kpiActiveCalls.textContent = "N/A";
    if (kpiConfigured) kpiConfigured.textContent = "0";
    if (kpiRegistered) kpiRegistered.textContent = "0";
    if (callMgrCallsActiveMraHosts) callMgrCallsActiveMraHosts.textContent = "-";
    if (callJabber) callJabber.textContent = "-";
    if (callTotal) callTotal.textContent = "-";
  }

  function renderPrefixRows(configured, registered) {
    const prefixes = ["CSF", "TCT", "BOT", "SEP"];
    prefixRows.innerHTML = prefixes
      .map((p) => '<tr><td class="mono">' + p + '</td><td class="mono">' + String((configured && configured[p]) || 0) + '</td><td class="mono">' + String((registered && registered[p]) || 0) + '</td></tr>')
      .join('');
  }

  async function loadStats() {
    try {
      const controller = new AbortController();
      const timeoutMs = 30000;
      const timeoutId = setTimeout(() => controller.abort(), timeoutMs);
      const resp = await fetch('/api/dashboard/stats', {
        method: "GET",
        credentials: "same-origin",
        headers: { Accept: "application/json", "X-Requested-With": "XMLHttpRequest" },
        signal: controller.signal,
      });
      clearTimeout(timeoutId);

      const payload = await resp.json();
      if (!resp.ok || !payload.ok) {
        throw new Error((payload && (payload.error || payload.detail)) || "Dashboard stats request failed");
      }

      const stats = payload.stats || {};
      if (kpiActiveCalls) kpiActiveCalls.textContent = stats.active_calls == null ? "N/A" : String(stats.active_calls);
      if (kpiConfigured) kpiConfigured.textContent = String(stats.jabber_csf_configured_total || 0);
      if (kpiRegistered) kpiRegistered.textContent = String(stats.jabber_csf_registered_total || 0);

      const callActivity = stats.call_activity || {};
      if (callMgrCallsActiveMraHosts) callMgrCallsActiveMraHosts.textContent = String(callActivity.callmanager_calls_active_on_mra_hosts || 0);
      if (callJabber) callJabber.textContent = String(callActivity.jabber_active_calls || 0);
      if (callTotal) callTotal.textContent = String(callActivity.total_active_calls || 0);

      renderPrefixRows(stats.configured_by_prefix || {}, stats.registered_by_prefix || {});

      if (lastRefreshEl) {
        lastRefreshEl.textContent = "Last refresh: " + new Date().toLocaleTimeString();
      }
    } catch (err) {
      renderErrorRows("Dashboard refresh failed: " + ((err && err.message) || "Unknown error"));
    }
  }

  function resetTimer() {
    if (timerId) {
      clearInterval(timerId);
      timerId = null;
    }
    if (!autoRefreshCb.checked) {
      return;
    }
    const seconds = parseInt(intervalSelect.value || "30", 10);
    timerId = setInterval(loadStats, Math.max(5, seconds) * 1000);
  }

  refreshBtn.addEventListener("click", loadStats);
  intervalSelect.addEventListener("change", resetTimer);
  autoRefreshCb.addEventListener("change", resetTimer);

  loadStats();
  resetTimer();
})();
"""

  return Response(
    content=js,
    media_type="application/javascript",
    headers={
      "Cache-Control": "no-store, no-cache, must-revalidate, max-age=0",
      "Pragma": "no-cache",
      "Expires": "0",
    },
  )


@app.get("/healthz")
def healthz():
  now_epoch = time.time()
  _prune_auth_sessions_locked(now_epoch)
  with AUDIT_LOG_LOCK:
    _ensure_audit_log()
    _prune_audit_log_locked()

  return JSONResponse(
    {
      "status": "ok",
      "service": "cucm-web",
      "timestamp": datetime.datetime.now().strftime(AUDIT_TIMESTAMP_FORMAT),
      "uptime_seconds": int(now_epoch - APP_START_EPOCH),
      "active_sessions": len(AUTH_SESSIONS),
      "job_output_cache_entries": len(JOB_OUTPUTS),
      "audit_log_exists": os.path.exists(AUDIT_LOG_PATH),
      "audit_retention_days": AUDIT_RETENTION_DAYS,
      "git_commit": _git_commit_short(),
      "feature_flags": {
        "preview_lab_only_default": PREVIEW_FEATURES_LAB_ONLY_DEFAULT,
        "sms_experimental_menu_enabled": SMS_EXPERIMENTAL_MENU_ENABLED,
        "sms_experimental_menu_lab_only": SMS_EXPERIMENTAL_MENU_LAB_ONLY,
        "integration_preflight_required": INTEGRATION_PREFLIGHT_REQUIRED,
      },
    }
  )


