@app.post("/teams-telephony/remove/lookup")
def teams_telephony_remove_lookup(
  request: Request,
  cucm_host: str = Form(""),
  cucm_user: str = Form(""),
  cucm_pass: str = Form(""),
  target_user: str = Form(...),
):
  cucm_host, cucm_user, cucm_pass = _resolve_cucm_credentials(request, cucm_host, cucm_user, cucm_pass)
  _update_cached_credentials(request, cucm_host=cucm_host, cucm_user=cucm_user)
  clean_target_user = (target_user or "").strip()
  if not clean_target_user:
    _append_audit_event(
      action="lookup_remove_teams_mapping",
      cucm_host=cucm_host,
      operator=cucm_user,
      target="account=(blank)",
      account="",
      extension_added="",
      extension_deleted="",
      output_filename="inline_json_error",
      inline_mode=True,
    )
    return JSONResponse({
      "ok": False,
      "error": {
        "message": "Target user is required.",
      },
    })

  try:
    result = lookup_teams_telephony_removal_candidate(
      cucm_host=cucm_host,
      cucm_user=cucm_user,
      cucm_pass=cucm_pass,
      target_user=clean_target_user,
    )
    _append_audit_event(
      action="lookup_remove_teams_mapping",
      cucm_host=cucm_host,
      operator=cucm_user,
      target=f"account={clean_target_user}",
      account=clean_target_user,
      extension_added="",
      extension_deleted="",
      output_filename="inline_json_ok",
      inline_mode=True,
    )
    return JSONResponse({"ok": True, **result})
  except Exception as exc:
    _append_audit_event(
      action="lookup_remove_teams_mapping",
      cucm_host=cucm_host,
      operator=cucm_user,
      target=f"account={clean_target_user}",
      account=clean_target_user,
      extension_added="",
      extension_deleted="",
      output_filename="inline_json_error",
      inline_mode=True,
    )
    return JSONResponse({
      "ok": False,
      "error": {
        "message": str(exc) or "Lookup failed.",
      },
    })


