@app.post("/translation-pattern/twilio-inbound-verification")
def twilio_inbound_verification_route(
    request: Request,
    cucm_host: str = Form(""),
    cucm_user: str = Form(""),
    cucm_pass: str = Form(""),
    profile_key: str = Form("phimane"),
    target_pattern: str = Form(""),
    restore_default: str = Form("0"),
):
    cucm_host, cucm_user, cucm_pass = _resolve_cucm_credentials(request, cucm_host, cucm_user, cucm_pass)
    _update_cached_credentials(request, cucm_host=cucm_host, cucm_user=cucm_user)

    profile = _get_twilio_inbound_verification_profile(profile_key)
    restore_mode = (restore_default or "").strip().lower() in {"1", "true", "yes", "on"}
    desired_pattern = profile.get("home_pattern", "") if restore_mode else (target_pattern or "").strip()
    if not desired_pattern:
      raise RuntimeError("Target translation pattern is required.")

    result = _update_twilio_inbound_verification_pattern(
      cucm_host=cucm_host,
      cucm_user=cucm_user,
      cucm_pass=cucm_pass,
      new_pattern=desired_pattern,
      profile_key=profile.get("key", ""),
    )

    auto_restore_enabled = False
    auto_restore_at_epoch_ms = 0
    if restore_mode:
      _cancel_twilio_inbound_auto_restore(profile.get("key", ""))
    elif desired_pattern != (profile.get("home_pattern", "") or ""):
      restore_at_epoch = _schedule_twilio_inbound_auto_restore(
        profile_key=profile.get("key", ""),
        cucm_host=cucm_host,
        cucm_user=cucm_user,
        cucm_pass=cucm_pass,
      )
      auto_restore_enabled = True
      auto_restore_at_epoch_ms = int(restore_at_epoch * 1000)
    else:
      _cancel_twilio_inbound_auto_restore(profile.get("key", ""))

    _append_audit_event(
      action="twilio_inbound_verification_update",
      cucm_host=cucm_host,
      operator=cucm_user,
      target=(
        f"profile={profile.get('key', '')};"
        f"description={profile.get('description', '')};"
        f"old={result.get('old_pattern', '')};new={result.get('new_pattern', '')}"
      ),
      output_filename="inline_json_ok",
      inline_mode=True,
    )

    return JSONResponse(
      {
        "ok": True,
        **result,
        "auto_restore_enabled": auto_restore_enabled,
        "auto_restore_at_epoch_ms": auto_restore_at_epoch_ms,
        "auto_restore_seconds": TWILIO_INBOUND_AUTO_RESTORE_SECONDS if auto_restore_enabled else 0,
      }
    )


@app.post("/inbound-callerid/block")
def block_inbound_callerid_route(
    request: Request,
    cucm_host: str = Form(""),
    cucm_user: str = Form(""),
    cucm_pass: str = Form(""),
    caller_id_number: str = Form(""),
    request_ticket: str = Form(""),
    action: str = Form("status"),
):
    cucm_host, cucm_user, cucm_pass = _resolve_cucm_credentials(request, cucm_host, cucm_user, cucm_pass)
    _update_cached_credentials(request, cucm_host=cucm_host, cucm_user=cucm_user)

    clean_action = (action or "status").strip().lower()
    if clean_action not in {"block", "remove", "delete", "status", "list"}:
      raise RuntimeError("action must be one of: block, remove, delete, status, list")

    clean_input = (caller_id_number or "").strip()
    pattern_value = ""
    normalized_number = ""

    if clean_action == "list":
      rows = _list_blocked_inbound_patterns(cucm_host, cucm_user, cucm_pass)
      _append_audit_event(
        action="block_inbound_calls_by_caller_id",
        cucm_host=cucm_host,
        operator=cucm_user,
        target="action=list",
        output_filename="inline_json_ok",
        inline_mode=True,
      )
      return JSONResponse({
        "ok": True,
        "action": "list",
        "count": len(rows),
        "results": rows,
      })

    pattern_value = _resolve_blocked_pattern_input(clean_input)
    normalized_number = _normalize_blocked_pattern_for_display(pattern_value)

    if clean_action == "block":
      description_text = _build_blocked_description(request_ticket)
      result = _add_blocked_inbound_pattern(
        cucm_host,
        cucm_user,
        cucm_pass,
        pattern_value,
        description_text,
      )
    elif clean_action in {"remove", "delete"}:
      result = _remove_blocked_inbound_pattern(cucm_host, cucm_user, cucm_pass, pattern_value)
      clean_action = "remove"
    else:
      result = _get_blocked_inbound_pattern_status(cucm_host, cucm_user, cucm_pass, pattern_value)

    _append_audit_event(
      action="block_inbound_calls_by_caller_id",
      cucm_host=cucm_host,
      operator=cucm_user,
      target=(
        f"caller_id={normalized_number};"
        f"pattern={pattern_value};"
        f"action={clean_action};"
        f"blocked={result.get('blocked', False)};"
        f"changed={result.get('changed', False)}"
      ),
      output_filename="inline_json_ok",
      inline_mode=True,
    )

    return JSONResponse({
      "ok": True,
      "action": clean_action,
      "caller_id_number": normalized_number,
      "pattern": result.get("pattern", pattern_value),
      "normalized_number": result.get("normalized_number", normalized_number),
      **result,
    })


