@app.get("/assets/page2-linegroup-search.js")
def page2_linegroup_search_js():
  js = r'''
(function () {
  function writeDebug(debugId, message, data) {
    const debugEl = document.getElementById(debugId);
    if (!debugEl) {
      return;
    }
    const stamp = new Date().toISOString();
    let line = `[${stamp}] ${message}`;
    if (typeof data !== "undefined") {
      if (typeof data === "string") {
        line += `\n${data}`;
      } else {
        try {
          line += `\n${JSON.stringify(data, null, 2)}`;
        } catch (_err) {
          line += `\n${String(data)}`;
        }
      }
    }
    debugEl.textContent = (line + "\n\n" + debugEl.textContent).slice(0, 20000);
  }

  async function runSearch(formId, statusId, debugId) {
    const form = document.getElementById(formId);
    const statusEl = document.getElementById(statusId);
    const selectEl = form ? form.querySelector('select[name="line_group_name"]') : null;
    const searchField = form ? form.querySelector('input[name="line_group_search"]') : null;

    if (!form || !statusEl || !selectEl) {
      writeDebug(debugId, "Search aborted: missing form/status/select", { formId, statusId });
      return;
    }

    writeDebug(debugId, "Search button clicked");
    statusEl.textContent = "Searching Line Groups...";

    while (selectEl.options.length > 1) {
      selectEl.remove(1);
    }
    selectEl.value = "";

    const initialSearch = String((searchField && searchField.value) || "").trim();
    writeDebug(debugId, "Search started", { endpoint: "/line-groups/search", query: initialSearch });

    try {
      const response = await fetch("/line-groups/search", {
        method: "POST",
        body: new FormData(form),
        credentials: "same-origin",
        headers: { "Accept": "application/json", "X-Requested-With": "XMLHttpRequest" },
      });

      const responseText = await response.text();
      writeDebug(debugId, "Primary response", { status: response.status, ok: response.ok, text: responseText.slice(0, 2000) });

      let payload = {};
      try {
        payload = responseText ? JSON.parse(responseText) : {};
      } catch (_parseErr) {
        payload = { matches: [] };
      }

      let matches = Array.isArray(payload.matches) ? payload.matches : [];

      if (!matches.length && initialSearch) {
        const fallbackFd = new FormData(form);
        fallbackFd.set("line_group_search", "");
        const fallbackResponse = await fetch("/line-groups/search", {
          method: "POST",
          body: fallbackFd,
          credentials: "same-origin",
          headers: { "Accept": "application/json", "X-Requested-With": "XMLHttpRequest" },
        });
        const fallbackText = await fallbackResponse.text();
        writeDebug(debugId, "Fallback response", { status: fallbackResponse.status, ok: fallbackResponse.ok, text: fallbackText.slice(0, 2000) });

        try {
          const fallbackPayload = fallbackText ? JSON.parse(fallbackText) : {};
          matches = Array.isArray(fallbackPayload.matches) ? fallbackPayload.matches : [];
        } catch (_parseErr) {
          matches = [];
        }
      }

      if (!matches.length) {
        statusEl.textContent = "No matching Line Groups found.";
        writeDebug(debugId, "Search completed with zero matches");
        return;
      }

      matches.forEach((name) => {
        const opt = document.createElement("option");
        opt.value = name;
        opt.textContent = name;
        selectEl.appendChild(opt);
      });

      if (matches.length === 1) {
        selectEl.value = matches[0];
      }

      statusEl.textContent = `Found ${matches.length} matching Line Group(s).`;
      writeDebug(debugId, "Search completed", { count: matches.length, first: matches[0] || "" });
    } catch (err) {
      statusEl.textContent = `Search failed: ${(err && err.message) || "Unknown error."}`;
      writeDebug(debugId, "Search exception", (err && err.stack) || (err && err.message) || String(err));
    }
  }

  async function runHuntMembersLookup() {
    const form = document.getElementById("admin-hunt-list-members-form");
    const statusEl = document.getElementById("admin-hunt-list-members-status");
    const resultsEl = document.getElementById("admin-hunt-list-members-results");
    const selectEl = form ? form.querySelector('select[name="line_group_name"]') : null;

    if (!form || !statusEl || !resultsEl || !selectEl) {
      return;
    }

    const selectedGroup = String(selectEl.value || "").trim();
    if (!selectedGroup) {
      statusEl.textContent = "Please select a matching Line Group first.";
      return;
    }

    statusEl.textContent = "Loading Hunt List members...";
    resultsEl.innerHTML = "";

    try {
      const response = await fetch("/line-groups/members", {
        method: "POST",
        body: new FormData(form),
        credentials: "same-origin",
        headers: { "Accept": "application/json", "X-Requested-With": "XMLHttpRequest" },
      });

      const responseText = await response.text();
      let payload = {};
      try {
        payload = responseText ? JSON.parse(responseText) : {};
      } catch (_parseErr) {
        payload = {};
      }

      if (!response.ok || !payload.ok) {
        throw new Error((payload && payload.error && payload.error.message) || payload.detail || payload.error || `Request failed with status ${response.status}`);
      }

      const members = payload.members || [];
      statusEl.textContent = `Hunt List "${payload.line_group_name || ""}" has ${members.length} member(s).`;

      if (!members.length) {
        resultsEl.innerHTML = "<p style=\"margin:0; color:#355978;\">No members found for this Hunt List.</p>";
        return;
      }

      let html = '<table style="width:100%; border-collapse:collapse; font-size:13px;">';
      html += '<thead><tr style="background:#005eb8; color:#fff;">';
      html += '<th style="padding:8px 10px; text-align:left; white-space:nowrap;">Extension</th>';
      html += '<th style="padding:8px 10px; text-align:left; white-space:nowrap;">Owner Name</th>';
      html += '<th style="padding:8px 10px; text-align:left; white-space:nowrap;">Route Partition</th>';
      html += '</tr></thead><tbody>';

      members.forEach((member, index) => {
        const bg = index % 2 === 0 ? "#f7fbff" : "#ffffff";
        html += '<tr style="background:' + bg + '; border-bottom:1px solid #c8dbee;">';
        html += '<td style="padding:7px 10px; font-family:Consolas,monospace;">' + (member.extension || "") + '</td>';
        html += '<td style="padding:7px 10px;">' + (member.owner_name || "Unknown") + '</td>';
        html += '<td style="padding:7px 10px; font-family:Consolas,monospace;">' + (member.partition || "") + '</td>';
        html += '</tr>';
      });

      html += '</tbody></table>';
      resultsEl.innerHTML = html;
    } catch (err) {
      statusEl.textContent = `Lookup failed: ${(err && err.message) || "Unknown error."}`;
    }
  }

  function bindButton(buttonId, formId, statusId, debugId) {
    const btn = document.getElementById(buttonId);
    if (!btn) {
      return;
    }
    btn.addEventListener("click", function (event) {
      event.preventDefault();
      runSearch(formId, statusId, debugId);
    });
    writeDebug(debugId, "Search handler bound", { buttonId });
  }

  function bindHuntMembersLookup() {
    const form = document.getElementById("admin-hunt-list-members-form");
    const btn = document.getElementById("admin-hunt-list-members-lookup-btn");
    if (!form || !btn) {
      return;
    }

    form.addEventListener("submit", function (event) {
      event.preventDefault();
      runHuntMembersLookup();
    });
    btn.addEventListener("click", function (event) {
      event.preventDefault();
      runHuntMembersLookup();
    });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", function () {
      bindButton("admin-hunt-list-search-btn", "admin-hunt-list-members-form", "admin-hunt-list-search-status", "admin-hunt-list-debug");
      bindButton("admin-line-group-search-btn", "admin-line-group-form", "admin-line-group-search-status", "admin-line-group-debug");
      bindHuntMembersLookup();
    });
  } else {
    bindButton("admin-hunt-list-search-btn", "admin-hunt-list-members-form", "admin-hunt-list-search-status", "admin-hunt-list-debug");
    bindButton("admin-line-group-search-btn", "admin-line-group-form", "admin-line-group-search-status", "admin-line-group-debug");
    bindHuntMembersLookup();
  }
})();
'''
  return Response(content=js, media_type="application/javascript")


